  details?: string;                // Additional context (e.g., "3 of 5 criteria defined")
}

/**
 * ReadinessChecklist - Checklist for determining if entity is ready
 *
 * Used to validate that a Task or Feature has complete requirements
 * before it can transition from draft to ready.
 */
export interface ReadinessChecklist {
  items: ReadinessCheckItem[];
  isReady: boolean;                // True if all items pass
  completedCount: number;          // Number of items that pass
  totalCount: number;              // Total number of items
}

/**
 * WorkflowSubmissionMetadata - Type-specific metadata for workflow submissions
 *
 * Stored in EvidenceSubmission.workflowMetadata for workflow-type submissions.
 */
export interface WorkflowSubmissionMetadata {
  // For feature_suggestion
  suggestedFeature?: {
    title: string;
