 * StackLayer - A layer in an organization's tech stack
 *
 * Layers represent architectural tiers (e.g., db, api, ui) and map to
 * specific agents and skills for planning workflows.
 *
 * Collection path: organizations/{orgId}/stackLayers/{layerId}
 */
export interface StackLayer {
  id: string;                    // Slug format: "api", "ml-pipeline", "infra"
  name: string;                  // Display name: "API Layer", "ML Pipeline"
  description: string;           // What this layer handles
  order: number;                 // Execution order (0-based)
  agentId?: string;              // Reference to OrgAgent.id
  skillIds: string[];            // References to skills
  validationChecklist: string[]; // Custom validation items (max 20, each max 500 chars)
  pathPatterns?: string[];       // Glob patterns defining which files belong to this layer (max 20, each max 200 chars)
  categoryMapping?: string[];    // Fallback: map file categories (server/ui/test) to this layer
  createdAt: string;
  updatedAt: string;
  deletedAt?: string | null;     // Soft delete timestamp
}

/**
