/**
 * Skill - Reusable skill stored in Firestore with content in GCS
 *
 * Skills provide instructions and guidelines that Claude can load
 * to enhance its capabilities for specific tasks.
 */
export interface Skill {
  id: string;
  name: string;                    // Unique within scope (kebab-case identifier)
  label?: string;                  // Human-readable display name (e.g., "Code Review Assistant"). Falls back to title-cased name if not set.
  slug: string;                    // URL-friendly name
  description: string;             // Short description for listing

  // Content (stored in GCS, loaded on demand)
  instructions: string;            // Main instructions (markdown)
  sections: Record<string, string>;  // Additional sections (e.g., "examples", "troubleshooting")
  scripts: SkillScript[];          // Associated scripts

  // Metadata
  tags: string[];
  version: string;                 // Semantic version (e.g., "1.0.0")
  scope: SkillScope;
  status: SkillStatus;             // Active, pending approval, or archived
  allowedTools: string[];          // Allowed tools for Claude (MCP tools, bash commands, etc.)
  license?: string;                // License information (e.g., "MIT", "proprietary")
  sdlcPhases?: string[];           // SDLC phases this skill applies to (e.g., ["planning", "coding", "review", "testing", "deploy", "debug"])
  metadata?: Record<string, string>;  // Additional key-value metadata

  // Ownership
  authorId: string;                // User who created
  orgId?: string;                  // Org scope (if applicable)
  teamId?: string;                 // Team scope (for team-scoped skills)

  // Content location (GCS or local file path)
