    type: 'flat' | 'directory';    // 'flat' = single file, 'directory' = SKILLS standard
    files: string[];               // List of files (e.g., ['references/COMPONENTS.md', 'scripts/validate.sh'])
    hasReferences: boolean;        // Has references/ subdirectory
    hasAssets: boolean;            // Has assets/ subdirectory
    hasScripts: boolean;           // Has scripts/ subdirectory
