/**
 * EvidenceType - Types of evidence that can be submitted
 *
 * Includes both traditional evidence types and workflow submission types:
 * - screenshot, video, log, test_result, other: Traditional evidence
 * - readiness_check: AI requests human to mark entity as ready
 * - feature_suggestion: AI suggests a new feature for review
 * - criteria_refinement: AI suggests improvements to acceptance criteria
 * - completion_review: AI submits completed work for final approval
 */
export type EvidenceType =
  | 'screenshot'
  | 'video'
  | 'log'
  | 'test_result'
  | 'other'
  // Workflow submission types (human-in-the-loop)
  | 'readiness_check'      // Request to mark entity as ready
  | 'feature_suggestion'   // AI-suggested feature for review
  | 'criteria_refinement'  // AI-suggested criteria improvement
  | 'completion_review';   // Request for final approval

export type VerificationType = 'screenshot' | 'test_output' | 'manual_check' | 'automated_test';
export type EvidenceReviewStatus = 'pending_review' | 'approved' | 'rejected' | 'needs_revision';

// =============================================================================
// HUMAN-IN-THE-LOOP WORKFLOW TYPES
// =============================================================================

/**
 * ReviewAction - Actions a human can take when reviewing submissions
 */
export type ReviewAction = 'approve' | 'reject' | 'request_changes';

/**
 * StatusGateType - Types of status gates that require human approval
 */
export type StatusGateType = 'draft_to_ready' | 'active_to_review' | 'review_to_done';

/**
 * ReviewRecord - Record of a human review decision
 *
 * Tracks who reviewed, when, what action was taken, and any feedback.
