// =============================================================================
// UNIFIED EPIC TYPES (Merged MCP + UI)
// These types replace both MCPEpic and Epic types with a single unified schema
// =============================================================================

/**
 * EpicStatus - Lifecycle status of an Epic
 *
 * Human-in-the-loop workflow: draft → planning → active → review → done
 * - draft: Initial state, requirements being defined
 * - planning: Tasks being added and organized
 * - active: Work in progress by AI agents
 * - review: All tasks submitted, awaiting human approval
 * - done: Human approved, work complete (replaces 'completed')
 * - blocked: Waiting on external dependencies (can enter from any state)
 */
export type EpicStatus =
  | 'draft'      // Initial state, requirements being defined
  | 'planning'   // Tasks being added and organized
  | 'active'     // Work in progress by AI agents
  | 'review'     // All tasks submitted, awaiting human approval
  | 'done'       // Human approved, work complete
  | 'blocked';   // Waiting on external dependencies

/**
 * TaskStatus - Status of a task within an Epic
 *
 * Human-in-the-loop workflow: draft → ready → active → review → done
 * - draft: Requirements being defined, AI can suggest features/criteria
 * - ready: Requirements complete, approved by human, can be claimed
 * - active: Claimed by AI, implementation in progress
 * - review: AI submitted work, awaiting human approval
 * - done: Human approved, task complete
 * - blocked: Waiting on dependencies (can enter from any state)
 */
export type TaskStatus =
  | 'draft'        // Requirements being defined
  | 'ready'        // Requirements complete, can be claimed by AI
  | 'active'       // Claimed and being worked on
  | 'review'       // Submitted for human approval
  | 'done'         // Human approved, complete
  | 'blocked';     // Waiting on dependencies

/**
 * FeatureStatus - Status of a feature within a task
 *
 * Human-in-the-loop workflow: draft → ready → active → review → done
 * - draft: Acceptance criteria being defined
 * - ready: Criteria complete, ready for implementation
 * - active: Being implemented by AI
 * - review: Evidence submitted, awaiting human approval
 * - done: Human approved evidence, feature complete
 * - blocked: Waiting on dependencies
 */
export type FeatureStatus =
  | 'draft'        // Acceptance criteria being defined
  | 'ready'        // Criteria complete, ready for implementation
  | 'active'       // Being implemented
  | 'review'       // Evidence submitted, awaiting approval
  | 'done'         // Human approved, complete
  | 'blocked';     // Waiting on dependencies

/**
 * EpicPriority - Priority level for Epics and Tasks
 * Includes 'critical' from MCP and standard levels from UI
 */
export type EpicPriority = 'low' | 'medium' | 'high' | 'critical';

/**
 * Epic - Unified Epic type for both MCP and UI workflows
 *
 * Supports two ID formats:
 * - MCP: "PREFIX-123" (shortKey + sequenceNum set)
 * - UI: UUID (shortKey + sequenceNum undefined)
 *
 * Progressive fields:
 * - All sources: id, title, status, source, organizationId
 * - MCP sessions: session claiming fields via tasks
 * - UI/Jira: jira fields, CI fields, deliverables
 */
export interface Epic {
  // Core identification
  id: string;                       // UUID or "PREFIX-123"

  // MCP-style ID components (optional - only for MCP-created Epics)
  shortKey?: string;                // "AUTH", "DATA" etc.
  sequenceNum?: number;             // Sequence number for "PREFIX-123" format

  // Basic metadata
  title: string;
  description?: string;

  // Source tracking
  source: EpicSource;               // 'mcp' | 'ui' | 'github'
  sourceRef?: string;               // GitHub issue URL, external reference

  // Ownership & organization
  organizationId: string;
  teamId?: string;                  // Optional team assignment
  createdBy: string;                // User ID who created
  ownerId?: string;                 // PM/lead responsible

  // Status & priority
  status: EpicStatus;
  priority: EpicPriority;

  // Timestamps
  createdAt: string;
  updatedAt: string;
  completedAt?: string;

  // Soft delete
  deletedAt?: string | null;
  deletedBy?: string | null;               // User ID or session ID who deleted

  // Metadata
  tags?: string[];

  // Jira integration (UI workflow)
  jiraKey?: string;                 // Linked Jira Epic key (e.g., "AUTH-100")
  jiraSyncEnabled?: boolean;
  lastJiraSyncAt?: string;

  // CI/CD integration (UI workflow)
  githubRepoUrl?: string;
  ciAutoValidate?: boolean;
  ciDeployPreview?: boolean;

  // Ticket integration — repo connection (TICKET-1 epic)
  githubRepoConnectionId?: string;      // RepoConnection.id used for issue/PR sync on this epic

  // Deliverables summary (UI workflow - for overview)
  deliverables?: {
    components?: number;
    endpoints?: number;
    schemas?: number;
    tests?: number;
  };

  // Activity tracking (UI workflow)
  recentActivity?: Array<{
    type: 'task_completed' | 'feature_added' | 'validation_passed' | 'asset_uploaded';
    description: string;
    timestamp: string;
  }>;

  // Human-in-the-loop workflow tracking
  statusHistory?: StatusTransition[];    // History of all status changes
  reviewHistory?: ReviewRecord[];        // History of human reviews
  pendingApprovalId?: string;            // ID of pending EvidenceSubmission awaiting review
}

/**
 * EpicTask - Task within an Epic
 * Stored separately in 'epicTasks' collection, referenced by epicId
 */
export interface EpicTask {
  id: string;                       // UUID
  epicId: string;                   // Parent Epic ID

  title: string;
  description?: string;

  // Task classification (optional - UI workflow)
  type?: EpicTaskType;              // 'story' | 'bug' | 'spike'

  // Status and assignment
  status: TaskStatus;
  priority: EpicPriority;

  // MCP session claiming (MCP workflow)
  claimedBySessionId?: string;      // Which session claimed this
  claimedAt?: string;
  lastActivityAt?: string;          // Last activity timestamp (for stale session detection)
  assignedTo?: string;              // Pre-assigned user ID

  // Dependencies
  dependsOn?: string[];             // Other task IDs
  blockedReason?: string;           // Why blocked

  // Jira integration (UI workflow)
  jiraKey?: string;                 // Linked Jira issue (e.g., "AUTH-101")

  // Soft delete
  deletedAt?: string | null;
  deletedBy?: string | null;               // User ID or session ID who deleted

  // Execution tracking
  startedAt?: string;
  completedAt?: string;

  // Metadata
  estimatedComplexity?: TaskComplexity;
  tags?: string[];

  // Timestamps
  createdAt: string;
  updatedAt: string;

  // Human-in-the-loop workflow tracking
  statusHistory?: StatusTransition[];    // History of all status changes
  reviewHistory?: ReviewRecord[];        // History of human reviews
  pendingApprovalId?: string;            // ID of pending EvidenceSubmission awaiting review
  readinessChecklist?: ReadinessChecklist;  // Current readiness state (for draft tasks)
  stackLayerIds?: string[];  // Stack layers this task touches

  // Ticket integration — GitHub Issues (TICKET-1 epic)
  githubIssueNumber?: number;           // Linked GitHub issue number
  githubIssueUrl?: string;             // Linked GitHub issue HTML URL
  githubIssueState?: 'open' | 'closed'; // Current state of linked GitHub issue
  githubSyncEnabled?: boolean;          // Whether GitHub sync is active for this task
  lastGithubSyncAt?: string;           // ISO timestamp of last successful GitHub sync

  // Ticket integration — Jira (TICKET-1 epic)
  jiraSyncEnabled?: boolean;            // Whether Jira sync is active for this task
  lastJiraSyncAt?: string;             // ISO timestamp of last successful Jira sync

  // Code change tracking (TICKET-1 epic)
  linkedPRs?: LinkedPullRequest[];      // Pull requests linked to this task
  linkedCommits?: LinkedCommit[];       // Commits linked to this task
  artifacts?: TaskArtifact[];           // Codebase artifacts produced during implementation
}

/**
 * EpicSummary - Lightweight Epic info for listing
 * Computed from Epic + aggregated Task/Feature counts
 */
export interface EpicSummary {
  id: string;
  title: string;
  status: EpicStatus;
  priority: EpicPriority;
  source: EpicSource;

