export type GitHubInstallationStatus = 'active' | 'suspended' | 'uninstalled';
export type RepoSyncMode = 'manual' | 'auto_approve';
export type RepoConnectionStatus = 'active' | 'disconnected';
export type SkillDeploymentStatus = 'pending' | 'pr_open' | 'deployed' | 'outdated' | 'removed';
export type SyncDirection = 'outbound' | 'inbound';

export type GitProviderType = 'github' | 'bitbucket';

export interface GitHubAppInstallation {
  id: string;                    // GitHub installation ID (numeric, stored as string)
  orgId: string;
  githubOrgLogin: string;        // GitHub org/user login name
  githubOrgId: number;           // GitHub org/user numeric ID
  permissions: {
    contents: string;            // 'write'
    pull_requests: string;       // 'write'
    metadata: string;            // 'read'
    issues?: string;             // 'write' — required for ticket integration
  };
  status: GitHubInstallationStatus;
  installedBy: string;           // userId
  installedAt: string;           // ISO timestamp
  updatedAt: string;
}

/**
 * LinkedPullRequest - A GitHub pull request linked to an EpicTask
 *
 * Captures key PR metadata at the time of linking, plus live state.
 * Stored as an array on EpicTask.linkedPRs.
 */
export interface LinkedPullRequest {
  number: number;                // GitHub PR number
  title: string;
  url: string;                   // HTML URL (e.g., https://github.com/org/repo/pull/42)
  state: 'open' | 'merged' | 'closed';
  author: string;                // GitHub login of PR author
  branch: string;                // Head branch name
  filesChanged: number;
  additions: number;
  deletions: number;
  linkedAt: string;              // ISO timestamp when linked to this task
  mergedAt?: string;             // ISO timestamp of merge (if merged)
}

/**
 * LinkedCommit - A Git commit linked to an EpicTask
 *
 * Captures the commit sha, message, and affected files.
 * Stored as an array on EpicTask.linkedCommits.
 */
export interface LinkedCommit {
  sha: string;                   // Full commit SHA
  message: string;
  author: string;                // GitHub login or display name
  timestamp: string;             // ISO timestamp of commit
  filesChanged: string[];        // Paths of files changed by this commit
}

/**
 * TaskArtifact - A codebase file artifact associated with an EpicTask
 *
 * Tracks source files, tests, snapshots, mocks, and config files produced
 * during task implementation. Can be linked to acceptance criteria or to
 * the PR/commit that introduced them.
 *
 * Stored as an array on EpicTask.artifacts.
 */
export interface TaskArtifact {
  id: string;                                                              // UUID
  path: string;                                                            // Relative file path in repo
  type: 'source' | 'test' | 'snapshot' | 'mock' | 'config';
  linkedCriteriaId?: string;                                               // Acceptance criteria this artifact satisfies
  addedFromPR?: number;                                                    // PR number that introduced this artifact
  addedFromCommit?: string;                                                // Commit SHA that introduced this artifact
}

/**
 * TicketStatusMapping - Maps external ticket statuses to aictrl task statuses
 *
 * Embedded on TicketSyncRule as statusMapping?.
 * Supports bidirectional mapping with per-mapping direction overrides.
 */
export interface TicketStatusMapping {
  id: string;
  orgId: string;
  provider: 'github' | 'jira';
  sourceProjectId: string;                    // GitHub repo full name or Jira project key
  mappings: Array<{
    externalStatus: string;                   // e.g., 'open', 'in-progress', 'done'
    externalStatusCategory?: string;          // Jira status category (e.g., 'To Do', 'In Progress', 'Done')
    aictrlStatus: TaskStatus;                 // Target aictrl task status
    direction: 'inbound' | 'outbound' | 'bidirectional';
  }>;
}

/**
 * TicketSyncRule - Configuration for syncing issues between an external tracker and aictrl
 *
 * Stored at: organizations/{orgId}/ticketSyncRules/{ruleId}
 *
 * Supports both GitHub Issues and Jira. Rules are evaluated in order when
 * a webhook event is received; the first matching rule wins.
 */
export interface TicketSyncRule {
  id: string;
  orgId: string;
  provider: 'github' | 'jira';
  sourceId: string;              // GitHub repo full name (e.g., "org/repo") or Jira project key
  targetEpicId?: string;         // Destination aictrl epic (if absent, creates new epics)
  direction: 'bidirectional' | 'inbound' | 'outbound';
  filters: {
    labels?: string[];           // Only sync issues with these labels
    excludeLabels?: string[];    // Exclude issues with these labels
    issueTypes?: string[];       // Jira issue types to sync (e.g., ['Story', 'Bug'])
    assigneeFilter?: string;     // Only sync issues assigned to this user
    sprintFilter?: string;       // Only sync issues in this sprint (Jira)
    issueState?: 'open' | 'closed' | 'all';  // GitHub issue state filter
    jql?: string;                // Raw JQL for advanced Jira filtering
  };
  options: {
    mapLabelsToType: boolean;    // Map GitHub labels / Jira issue types to EpicTaskType
    autoCloseOnDone: boolean;    // Close external ticket when task reaches 'done'
    importComments: boolean;     // Import comments from external tracker
    syncPriority: boolean;       // Sync priority field bidirectionally
  };
  enabled: boolean;
  createdAt: string;
  updatedAt: string;
  statusMapping?: TicketStatusMapping;  // Optional custom status mapping for this rule
}


