      .where('featureId', '==', filters.featureId);

    if (filters.criteriaId) {
      query = query.where('criteriaId', '==', filters.criteriaId);
    }

    if (filters.reviewStatus) {
      query = query.where('reviewStatus', '==', filters.reviewStatus);
    }

    const snapshot = await query.orderBy('submittedAt', 'desc').get();

    return snapshot.docs.map(doc => doc.data() as EvidenceSubmission);
  }

  /**
   * Get a single evidence submission
   */
  async getEvidenceSubmission(submissionId: string): Promise<EvidenceSubmission | null> {
    const doc = await this.db.collection('evidenceSubmissions').doc(submissionId).get();
    if (!doc.exists) return null;
    return doc.data() as EvidenceSubmission;
  }

  /**
   * Review an evidence submission
   */
  async reviewEvidenceSubmission(
    submissionId: string,
    action: 'approve' | 'reject' | 'request_revision',
    reviewedBy: string,
    comment?: string
  ): Promise<EvidenceSubmission> {
    const ref = this.db.collection('evidenceSubmissions').doc(submissionId);
    const doc = await ref.get();

    if (!doc.exists) {
      throw new Error(`Evidence submission ${submissionId} not found`);
    }

    const statusMap: Record<string, EvidenceReviewStatus> = {
      approve: 'approved',
      reject: 'rejected',
      request_revision: 'needs_revision',
    };

    const now = new Date().toISOString();
    const updates: Partial<EvidenceSubmission> & { reviewComment?: string } = {
      reviewStatus: statusMap[action],
      reviewedAt: now,
      reviewedBy,
    };

    if (comment) {
      updates.reviewComment = comment;
    }

    await ref.update(updates);

    const updated = await ref.get();
    return updated.data() as EvidenceSubmission;
  }

