  /**
   * Create a task within an Epic
   */
  async createTask(request: CreateEpicTaskRequest): Promise<EpicTask> {
    const now = new Date().toISOString();
    const taskId = uuidv4();

    const task: EpicTask = {
      id: taskId,
      epicId: request.epicId,
      title: request.title,
      status: 'draft',  // New tasks start in draft status (requirements being defined)
      priority: request.priority || 'medium',
      createdAt: now,
      updatedAt: now,
      deletedAt: null, // Soft delete tracking
    };

    // Add optional fields only if defined
    if (request.description !== undefined) task.description = request.description;
    if (request.type !== undefined) task.type = request.type;
    if (request.assignedTo !== undefined) task.assignedTo = request.assignedTo;
    if (request.dependsOn !== undefined) task.dependsOn = request.dependsOn;
    if (request.estimatedComplexity !== undefined) task.estimatedComplexity = request.estimatedComplexity;
    if (request.tags !== undefined) task.tags = request.tags;
    if (request.jiraKey !== undefined) task.jiraKey = request.jiraKey;
    if (request.stackLayerIds !== undefined) task.stackLayerIds = request.stackLayerIds;

    await this.db.collection('epicTasks').doc(taskId).set(task);
    return task;
  }

  /**
   * Get a task by ID
   * @param taskId - Task ID to retrieve
   * @param options - Optional settings
   * @param options.includeDeleted - If true, return soft-deleted tasks (for verification)
   */
  async getTask(taskId: string, options?: { includeDeleted?: boolean }): Promise<EpicTask | null> {
    const doc = await this.db.collection('epicTasks').doc(taskId).get();
    if (!doc.exists) return null;
    const task = doc.data() as EpicTask;
    // Return null if soft-deleted (deletedAt is a timestamp string)
    // Don't filter if deletedAt is null or undefined (not deleted)
    if (task.deletedAt && !options?.includeDeleted) return null;
    return task;
  }

  /**
   * List tasks for an Epic
   */
  async listTasks(epicId: string, filters?: EpicTaskFilters): Promise<EpicTask[]> {
    let query = this.db.collection('epicTasks')
      .where('epicId', '==', epicId)
      .where('deletedAt', '==', null); // Filter soft-deleted at database level

    // Apply Firestore-supported filters
    if (filters?.status) {
      query = query.where('status', '==', filters.status);
    }
    if (filters?.type) {
      query = query.where('type', '==', filters.type);
    }
    if (filters?.priority) {
      query = query.where('priority', '==', filters.priority);
    }
    if (filters?.assignedTo) {
      query = query.where('assignedTo', '==', filters.assignedTo);
    }
    if (filters?.claimedBySession) {
      query = query.where('claimedBySessionId', '==', filters.claimedBySession);
    }

    const snapshot = await query.orderBy('createdAt', 'asc').get();
    let tasks = snapshot.docs.map(doc => doc.data() as EpicTask);

    // Apply in-memory filters
    if (filters?.search) {
      const searchLower = filters.search.toLowerCase();
      tasks = tasks.filter(t =>
        t.title.toLowerCase().includes(searchLower) ||
        t.description?.toLowerCase().includes(searchLower)
      );
    }

    return tasks;
  }

  /**
   * Batch list tasks for multiple epics (optimized to avoid N+1 queries)
   * Returns a map of epicId to tasks array
   */
  async listTasksForEpics(epicIds: string[]): Promise<Map<string, EpicTask[]>> {
    if (epicIds.length === 0) {
      return new Map();
    }

    // Batch query all tasks for these epics (Firestore 'in' supports max 10 items)
    const allTasks: EpicTask[] = [];
    for (let i = 0; i < epicIds.length; i += 10) {
      const batch = epicIds.slice(i, i + 10);
      const tasksSnapshot = await this.db.collection('epicTasks')
        .where('epicId', 'in', batch)
        .where('deletedAt', '==', null)
        .orderBy('createdAt', 'asc')
        .get();
      const tasks = tasksSnapshot.docs.map(doc => doc.data() as EpicTask);
      allTasks.push(...tasks);
    }

    // Group tasks by epicId
    const tasksByEpic = new Map<string, EpicTask[]>();
    for (const task of allTasks) {
      if (!tasksByEpic.has(task.epicId)) {
        tasksByEpic.set(task.epicId, []);
      }
      tasksByEpic.get(task.epicId)!.push(task);
    }

    return tasksByEpic;
  }

