  async createOrganization(name: string, ownerId: string): Promise<Organization> {
    const orgId = uuidv4();
    const now = new Date().toISOString();

    const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

    const org: Organization = {
      id: orgId,
      name,
      ownerId,
      slug,
      createdAt: now,
      updatedAt: now,
      deletedAt: null, // Soft delete tracking
      members: {
        [ownerId]: {
          userId: ownerId,
          role: 'owner',
          joinedAt: now,
        },
      },
    };

    await this.db.collection('organizations').doc(orgId).set(org);
    return org;
  }

  async getOrganization(orgId: string, options?: { includeDeleted?: boolean }): Promise<Organization | null> {
    const doc = await this.db.collection('organizations').doc(orgId).get();
    if (!doc.exists) return null;
    const org = doc.data() as Organization;
    if (org.deletedAt && !options?.includeDeleted) return null;
    return org;
  }

  async listUserOrganizations(userId: string): Promise<Organization[]> {
    const snapshot = await this.db
      .collection('organizations')
      .where(`members.${userId}`, '!=', null)
      .get();

    return snapshot.docs.map(doc => doc.data() as Organization);
  }

  async ensurePersonalOrganization(userId: string): Promise<Organization | null> {
    const orgs = await this.listUserOrganizations(userId);
    const personalOrg = orgs.find(org => org.ownerId === userId && org.slug.startsWith('personal-'));

    if (personalOrg) {
      return personalOrg;
    }

    return this.createOrganization(`Personal - ${userId.substring(0, 8)}`, userId);
  }

