  /**
   * Add a comment to an evidence submission
   */
  async addEvidenceComment(
    evidenceId: string,
    content: string,
    createdBy: string,
    options?: {
      parentId?: string;
      position?: { x: number; y: number };
    }
  ): Promise<EvidenceComment> {
    // Verify the evidence submission exists
    const evidenceRef = this.db.collection('evidenceSubmissions').doc(evidenceId);
    const evidenceDoc = await evidenceRef.get();
    if (!evidenceDoc.exists) {
      throw new Error(`Evidence submission ${evidenceId} not found`);
    }

    // If this is a reply, verify the parent exists
    if (options?.parentId) {
      const parentRef = this.db.collection('evidenceComments').doc(options.parentId);
      const parentDoc = await parentRef.get();
      if (!parentDoc.exists) {
        throw new Error(`Parent comment ${options.parentId} not found`);
      }
    }

    // Validate position coordinates if provided (defense-in-depth)
    if (options?.position) {
      const { x, y } = options.position;
      if (typeof x !== 'number' || typeof y !== 'number') {
        throw new Error('Position must have x and y as numbers');
      }
      if (x < 0 || x > 100 || y < 0 || y > 100) {
        throw new Error('Position x and y must be between 0 and 100');
      }
    }

    const now = new Date().toISOString();
    const commentId = uuidv4();

    const comment: EvidenceComment = {
      id: commentId,
      evidenceId,
      content,
      createdBy,
      createdAt: now,
    };

    if (options?.parentId) {
      comment.parentId = options.parentId;
    }

    if (options?.position) {
      comment.position = options.position;
    }

    await this.db.collection('evidenceComments').doc(commentId).set(comment);
    return comment;
  }

  /**
   * List comments for an evidence submission with pagination
   */
  async listEvidenceComments(
    evidenceId: string,
    options?: { limit?: number; offset?: number }
  ): Promise<EvidenceComment[]> {
    const limit = options?.limit || 100;
    const offset = options?.offset || 0;

    let query = this.db
      .collection('evidenceComments')
      .where('evidenceId', '==', evidenceId)
      .orderBy('createdAt', 'asc');

    // Apply pagination
    if (offset > 0) {
      query = query.offset(offset);
    }
    query = query.limit(limit);

    const snapshot = await query.get();
    return snapshot.docs.map(doc => doc.data() as EvidenceComment);
  }

  /**
   * Get a single comment by ID
   */
  async getEvidenceComment(commentId: string): Promise<EvidenceComment | null> {
    const doc = await this.db.collection('evidenceComments').doc(commentId).get();
    if (!doc.exists) return null;
    return doc.data() as EvidenceComment;
  }

  /**
   * Update a comment's content
   */
  async updateEvidenceComment(
    commentId: string,
    content: string,
    updatedBy: string
  ): Promise<EvidenceComment> {
    const ref = this.db.collection('evidenceComments').doc(commentId);
    const doc = await ref.get();

    if (!doc.exists) {
      throw new Error(`Comment ${commentId} not found`);
    }

    const existing = doc.data() as EvidenceComment;

    // Only the creator can update their comment
    if (existing.createdBy !== updatedBy) {
      throw new Error('Only the comment author can edit this comment');
    }

    const now = new Date().toISOString();
    await ref.update({
      content,
      updatedAt: now,
    });

    const updated = await ref.get();
    return updated.data() as EvidenceComment;
  }

  /**
   * Delete a comment and its replies using a transaction for atomicity
   */
  async deleteEvidenceComment(commentId: string, deletedBy: string): Promise<void> {
    const ref = this.db.collection('evidenceComments').doc(commentId);

    await this.db.runTransaction(async (transaction) => {
      const doc = await transaction.get(ref);

      if (!doc.exists) {
        throw new Error(`Comment ${commentId} not found`);
      }

      const existing = doc.data() as EvidenceComment;

      // Only the creator can delete their comment
      if (existing.createdBy !== deletedBy) {
        throw new Error('Only the comment author can delete this comment');
      }

      // Get all replies to this comment
      const repliesSnapshot = await this.db
        .collection('evidenceComments')
        .where('parentId', '==', commentId)
        .get();

      // Delete the comment and all its replies in the transaction
      transaction.delete(ref);
      repliesSnapshot.docs.forEach(reply => transaction.delete(reply.ref));
    });
  }

  /**
   * Resolve a comment (mark as addressed)
   */
  async resolveEvidenceComment(
    commentId: string,
    resolvedBy: string
  ): Promise<EvidenceComment> {
    const ref = this.db.collection('evidenceComments').doc(commentId);
    const doc = await ref.get();

    if (!doc.exists) {
      throw new Error(`Comment ${commentId} not found`);
    }

    const now = new Date().toISOString();
    await ref.update({
      resolved: true,
      resolvedAt: now,
      resolvedBy,
    });

    const updated = await ref.get();
    return updated.data() as EvidenceComment;
  }

  /**
   * Unresolve a comment
   */
  async unresolveEvidenceComment(commentId: string): Promise<EvidenceComment> {
    const ref = this.db.collection('evidenceComments').doc(commentId);
    const doc = await ref.get();

    if (!doc.exists) {
      throw new Error(`Comment ${commentId} not found`);
    }

    await ref.update({
      resolved: FieldValue.delete(),
      resolvedAt: FieldValue.delete(),
      resolvedBy: FieldValue.delete(),
    });

    const updated = await ref.get();
    return updated.data() as EvidenceComment;
  }
}

