  /**
   * Create a task within an Epic
   */
  async createTask(request: CreateEpicTaskRequest): Promise<EpicTask> {
    const now = new Date().toISOString();
    const taskId = uuidv4();

    const task: EpicTask = {
      id: taskId,
      epicId: request.epicId,
      title: request.title,
      status: 'draft',  // New tasks start in draft status (requirements being defined)
      priority: request.priority || 'medium',
      createdAt: now,
      updatedAt: now,
      deletedAt: null, // Soft delete tracking
    };

    // Add optional fields only if defined
    if (request.description !== undefined) task.description = request.description;
    if (request.type !== undefined) task.type = request.type;
    if (request.assignedTo !== undefined) task.assignedTo = request.assignedTo;
    if (request.dependsOn !== undefined) task.dependsOn = request.dependsOn;
    if (request.estimatedComplexity !== undefined) task.estimatedComplexity = request.estimatedComplexity;
    if (request.tags !== undefined) task.tags = request.tags;
    if (request.jiraKey !== undefined) task.jiraKey = request.jiraKey;
    if (request.stackLayerIds !== undefined) task.stackLayerIds = request.stackLayerIds;

    await this.db.collection('epicTasks').doc(taskId).set(task);
    return task;
  }

