  /**
   * List tasks for an Epic
   */
  async listTasks(epicId: string, filters?: EpicTaskFilters): Promise<EpicTask[]> {
    let query = this.db.collection('epicTasks')
      .where('epicId', '==', epicId)
      .where('deletedAt', '==', null); // Filter soft-deleted at database level

    // Apply Firestore-supported filters
    if (filters?.status) {
      query = query.where('status', '==', filters.status);
    }
    if (filters?.type) {
      query = query.where('type', '==', filters.type);
    }
    if (filters?.priority) {
      query = query.where('priority', '==', filters.priority);
    }
    if (filters?.assignedTo) {
      query = query.where('assignedTo', '==', filters.assignedTo);
    }
    if (filters?.claimedBySession) {
      query = query.where('claimedBySessionId', '==', filters.claimedBySession);
    }

    const snapshot = await query.orderBy('createdAt', 'asc').get();
    let tasks = snapshot.docs.map(doc => doc.data() as EpicTask);

    // Apply in-memory filters
    if (filters?.search) {
      const searchLower = filters.search.toLowerCase();
      tasks = tasks.filter(t =>
        t.title.toLowerCase().includes(searchLower) ||
        t.description?.toLowerCase().includes(searchLower)
      );
    }

    return tasks;
  }

  /**
   * Batch list tasks for multiple epics (optimized to avoid N+1 queries)
   * Returns a map of epicId to tasks array
   */
  async listTasksForEpics(epicIds: string[]): Promise<Map<string, EpicTask[]>> {
    if (epicIds.length === 0) {
      return new Map();
    }

    // Batch query all tasks for these epics (Firestore 'in' supports max 10 items)
    const allTasks: EpicTask[] = [];
    for (let i = 0; i < epicIds.length; i += 10) {
      const batch = epicIds.slice(i, i + 10);
      const tasksSnapshot = await this.db.collection('epicTasks')
        .where('epicId', 'in', batch)
        .where('deletedAt', '==', null)
        .orderBy('createdAt', 'asc')
        .get();
      const tasks = tasksSnapshot.docs.map(doc => doc.data() as EpicTask);
      allTasks.push(...tasks);
    }

    // Group tasks by epicId
    const tasksByEpic = new Map<string, EpicTask[]>();
    for (const task of allTasks) {
      if (!tasksByEpic.has(task.epicId)) {
        tasksByEpic.set(task.epicId, []);
      }
      tasksByEpic.get(task.epicId)!.push(task);
    }

    return tasksByEpic;
  }

