  async createTeamStackLayer(
    teamId: string,
    _orgId: string,
    request: CreateTeamStackLayerRequest
  ): Promise<TeamStackLayer> {
    const now = new Date().toISOString();
    const layer: Omit<TeamStackLayer, 'id'> = {
      teamId,
      name: request.name.trim(),
      description: request.description?.trim() || '',
      order: request.order ?? 0,
      overridesOrgLayer: request.overridesOrgLayer,
      skillIds: request.skillIds || [],
      validationChecklist: request.validationChecklist || [],
      createdAt: now,
      updatedAt: now,
      deletedAt: null,
      disabled: request.disabled ?? false,
      ...(request.agentId !== undefined && { agentId: request.agentId }),
    };

    await this.db
      .collection('teams')
      .doc(teamId)
      .collection('stackLayers')
      .doc(request.id)
      .set(layer);

    return { id: request.id, ...layer } as TeamStackLayer;
  }

  async updateTeamStackLayer(
    teamId: string,
    layerId: string,
    updates: UpdateTeamStackLayerRequest
  ): Promise<TeamStackLayer> {
    const existing = await this.getTeamStackLayer(teamId, layerId);
    if (!existing) {
      log.error({ teamId, layerId }, 'updateTeamStackLayer: layer not found');
      throw new Error(`Layer "${layerId}" not found in team`);
    }

    const now = new Date().toISOString();
    const updateData: Record<string, unknown> = { updatedAt: now };

    if (updates.name !== undefined) updateData.name = updates.name.trim();
    if (updates.description !== undefined) updateData.description = updates.description.trim();
    if (updates.agentId !== undefined) {
      if (updates.agentId === null) {
        const { FieldValue } = await import('firebase-admin/firestore');
        updateData.agentId = FieldValue.delete();
      } else {
        updateData.agentId = updates.agentId;
      }
    }
    if (updates.skillIds !== undefined) updateData.skillIds = updates.skillIds;
    if (updates.validationChecklist !== undefined) {
      updateData.validationChecklist = updates.validationChecklist
        .map((item) => item.trim())
        .filter((item) => item.length > 0);
    }
    if (updates.disabled !== undefined) updateData.disabled = updates.disabled;

    await this.db
      .collection('teams')
      .doc(teamId)
      .collection('stackLayers')
      .doc(layerId)
      .update(updateData);

    return { ...existing, ...updateData } as TeamStackLayer;
  }

