  ValidationItem,
} from './types.js';

const DATA_DIR = path.join(process.cwd(), 'data', 'sessions');

async function ensureDir(dir: string): Promise<void> {
  try {
    await fs.mkdir(dir, { recursive: true });
  } catch {
    // Directory exists
  }
}

async function readJson<T>(filePath: string, defaultValue: T): Promise<T> {
  try {
    const content = await fs.readFile(filePath, 'utf-8');
    return JSON.parse(content) as T;
  } catch {
    return defaultValue;
  }
}

async function writeJson<T>(filePath: string, data: T): Promise<void> {
  await fs.writeFile(filePath, JSON.stringify(data, null, 2), 'utf-8');
}

function sessionDir(sessionId: string): string {
  return path.join(DATA_DIR, sessionId);
}

export class StateManager {
  private inputResolvers: Map<string, (response: string, respondedBy: string) => void> = new Map();

  async createSession(name?: string, useNameAsId: boolean = false, userId?: string, organizationId?: string): Promise<Session> {
    // Generate a human-readable ID if no name provided
    const sessionName = name || humanId({ separator: '-', capitalize: false });
    const id = useNameAsId ? sessionName : uuidv4();
    const now = new Date().toISOString();

    const session: Session = {
      id,
      name: sessionName,
      userId,
      organizationId,
      visibility: 'private',
      createdAt: now,
      updatedAt: now,
      status: 'active',
    };

    const dir = sessionDir(id);
    await ensureDir(dir);

    await Promise.all([
      writeJson(path.join(dir, 'session.json'), session),
      writeJson(path.join(dir, 'tasks.json'), []),           // @deprecated - kept for compatibility
      writeJson(path.join(dir, 'features.json'), []),
      writeJson(path.join(dir, 'inputs.json'), []),
      writeJson(path.join(dir, 'checkpoints.json'), []),     // @deprecated - checkpoints now in features
      writeJson(path.join(dir, 'progress-logs.json'), []),   // New: narrative progress log
    ]);

    return session;
  }

  async listSessions(userId?: string, organizationId?: string): Promise<Session[]> {
    await ensureDir(DATA_DIR);

    try {
      const entries = await fs.readdir(DATA_DIR, { withFileTypes: true });
      const sessions: Session[] = [];

      for (const entry of entries) {
        if (entry.isDirectory()) {
          const session = await this.getSession(entry.name);
          if (session) {
            // Filter by organizationId if provided
            if (organizationId) {
              if (session.organizationId === organizationId) {
                sessions.push(session);
              }
            }
            // Filter by userId if provided (and no org filter)
            else if (!userId || session.userId === userId || !session.userId) {
              sessions.push(session);
            }
          }
        }
      }

      return sessions.sort((a, b) =>
        new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      );
    } catch {
      return [];
    }
  }

  async getSession(sessionId: string): Promise<Session | null> {
    try {
      return await readJson<Session | null>(
        path.join(sessionDir(sessionId), 'session.json'),
        null
      );
    } catch {
      return null;
    }
  }

  async getSessionState(sessionId: string): Promise<SessionState | null> {
    const session = await this.getSession(sessionId);
    if (!session) return null;

    const dir = sessionDir(sessionId);
    const [progressLogs, pendingInputs] = await Promise.all([
      readJson<ProgressLog[]>(path.join(dir, 'progress-logs.json'), []),
      readJson<PendingInput[]>(path.join(dir, 'inputs.json'), []),
    ]);

    return { session, progressLogs, pendingInputs };
  }

  async updateSession(
    sessionId: string,
    updates: { visibility?: SessionVisibility; organizationId?: string }
  ): Promise<Session | null> {
    const sessionPath = path.join(sessionDir(sessionId), 'session.json');
    const session = await readJson<Session | null>(sessionPath, null);

    if (!session) return null;

    const now = new Date().toISOString();

    if (updates.visibility !== undefined) {
      session.visibility = updates.visibility;
    }
    if (updates.organizationId !== undefined) {
      session.organizationId = updates.organizationId;
    }
    session.updatedAt = now;

    await writeJson(sessionPath, session);
    return session;
  }

  // ==========================================================================
  // NEW: Progress Log Methods (replaces Task-based progress tracking)
  // ==========================================================================

  async getProgressLogs(sessionId: string): Promise<ProgressLog[]> {
    return readJson<ProgressLog[]>(
      path.join(sessionDir(sessionId), 'progress-logs.json'),
      []
    );
  }

  async logProgress(sessionId: string, request: ProgressLogRequest): Promise<ProgressLog> {
    const logsPath = path.join(sessionDir(sessionId), 'progress-logs.json');
    const logs = await readJson<ProgressLog[]>(logsPath, []);

    const entry: ProgressLog = {
      id: uuidv4(),
      summary: request.summary,
      featureId: request.featureId,
      createdAt: new Date().toISOString(),
    };

    logs.push(entry);
    await writeJson(logsPath, logs);
    await this.updateSessionTimestamp(sessionId);

    return entry;
  }


  async getPendingInputs(sessionId: string): Promise<PendingInput[]> {
    const inputs = await readJson<PendingInput[]>(
      path.join(sessionDir(sessionId), 'inputs.json'),
      []
    );
    return inputs.filter(i => !i.respondedAt);
  }

  async createInputRequest(sessionId: string, request: InputRequest): Promise<PendingInput> {
    const inputsPath = path.join(sessionDir(sessionId), 'inputs.json');
    const inputs = await readJson<PendingInput[]>(inputsPath, []);

    const pendingInput: PendingInput = {
      id: uuidv4(),
      prompt: request.prompt,
      context: request.context,
      urgency: request.urgency || 'normal',
      options: request.options,
      timeoutMinutes: request.timeoutMinutes || 60,
      createdAt: new Date().toISOString(),
    };

    inputs.push(pendingInput);
    await writeJson(inputsPath, inputs);
    await this.updateSessionTimestamp(sessionId);

    return pendingInput;
  }

  async waitForInputResponse(
    sessionId: string,
    inputId: string,
    timeoutMinutes: number
  ): Promise<{ response: string; respondedBy: string } | null> {
    return new Promise((resolve) => {
      const timeoutMs = timeoutMinutes * 60 * 1000;

      const timeout = setTimeout(() => {
        this.inputResolvers.delete(inputId);
        resolve(null);
      }, timeoutMs);

      this.inputResolvers.set(inputId, (response: string, respondedBy: string) => {
        clearTimeout(timeout);
        this.inputResolvers.delete(inputId);
        resolve({ response, respondedBy });
      });
    });
  }

  async respondToInput(
    sessionId: string,
    inputId: string,
    response: string,
    respondedBy: string
  ): Promise<PendingInput | null> {
    const inputsPath = path.join(sessionDir(sessionId), 'inputs.json');
    const inputs = await readJson<PendingInput[]>(inputsPath, []);

    const input = inputs.find(i => i.id === inputId);
    if (!input) return null;

    const now = new Date().toISOString();
    input.response = response;
    input.respondedBy = respondedBy;
    input.respondedAt = now;

    await writeJson(inputsPath, inputs);
    await this.updateSessionTimestamp(sessionId);

    // Resolve waiting promise
    const resolver = this.inputResolvers.get(inputId);
    if (resolver) {
      resolver(response, respondedBy);
    }

    return input;
  }

  async createCheckpoint(sessionId: string, request: CheckpointRequest): Promise<Checkpoint> {
    const checkpointsPath = path.join(sessionDir(sessionId), 'checkpoints.json');
    const checkpoints = await readJson<Checkpoint[]>(checkpointsPath, []);

    const checkpoint: Checkpoint = {
      id: uuidv4(),
      summary: request.summary,
      artifacts: request.artifacts,
      state: request.state,
      createdAt: new Date().toISOString(),
    };

    checkpoints.push(checkpoint);

    // Keep only last 50 checkpoints
    const trimmedCheckpoints = checkpoints.slice(-50);
    await writeJson(checkpointsPath, trimmedCheckpoints);
    await this.updateSessionTimestamp(sessionId);

    return checkpoint;
  }

