  private async updateSessionTimestamp(sessionId: string): Promise<void> {
    const sessionPath = path.join(sessionDir(sessionId), 'session.json');
    const session = await readJson<Session | null>(sessionPath, null);

    if (session) {
      session.updatedAt = new Date().toISOString();
      await writeJson(sessionPath, session);
    }
  }

  async deleteSession(sessionId: string): Promise<boolean> {
    const dir = sessionDir(sessionId);
    try {
      await fs.rm(dir, { recursive: true, force: true });
      return true;
    } catch (error) {
      log.error({ err: error }, `Failed to delete session ${sessionId}:`);
      return false;
    }
  }

  async deleteSessions(sessionIds: string[]): Promise<{ deleted: string[]; failed: string[] }> {
    const results = await Promise.all(
      sessionIds.map(async (id) => ({
        id,
        success: await this.deleteSession(id),
      }))
    );

    return {
      deleted: results.filter(r => r.success).map(r => r.id),
      failed: results.filter(r => !r.success).map(r => r.id),
    };
  }

