/**
 * Move a task and all its features to a different epic
 * Uses batch operations for optimal performance
 *
 * @param taskId - Task ID to move
 * @param targetEpicId - Target Epic ID
 */
async moveTask(taskId: string, targetEpicId: string): Promise<EpicTask> {
  const now = new Date().toISOString();

  // Get the task
  const taskRef = this.db.collection('epicTasks').doc(taskId);
  const taskDoc = await taskRef.get();
  if (!taskDoc.exists) {
    throw new Error(`Task ${taskId} not found`);
  }

  const task = taskDoc.data() as EpicTask;

  // Verify target epic exists
  const targetEpic = await this.getEpic(targetEpicId);
  if (!targetEpic) {
    throw new Error(`Target epic ${targetEpicId} not found`);
  }

  // Get all features for this task
  const features = await this.listFeatures(taskId);

  log.info(`Moving task ${taskId} from epic ${task.epicId} to ${targetEpicId}: ${features.length} features`);

  // Batch update all entities
  const batch = this.db.batch();

  // Update features' epicId (denormalized field)
  for (const feature of features) {
    batch.update(this.db.collection('features').doc(feature.id), {
      epicId: targetEpicId,
      updatedAt: now
    });
  }

  // Update task's epicId
  batch.update(taskRef, {
    epicId: targetEpicId,
    updatedAt: now
  });

  await batch.commit();
  log.info(`Task ${taskId} and ${features.length} features moved to epic ${targetEpicId}`);

  // Return updated task
  const updated = await taskRef.get();
  return updated.data() as EpicTask;
}

