  /**
   * Submit evidence for review (creates EvidenceSubmission)
   */
  async submitEvidence(request: {
    organizationId: string;
    epicId: string;
    taskId: string;
    featureId: string;
    criteriaId: string;
    sessionId: string;
    type: EvidenceType;
    title?: string;
    description?: string;
    url?: string;
    base64?: string;
    text?: string;
    mimeType?: string;
    testResults?: TestResults;
  }): Promise<EvidenceSubmission> {
    const now = new Date().toISOString();
    const id = uuidv4();

    // Get current version count for this criteria
    const existingSubmissions = await this.db
      .collection('evidenceSubmissions')
      .where('criteriaId', '==', request.criteriaId)
      .get();

    const version = existingSubmissions.size + 1;

    // Calculate size if base64 is provided
    let size: number | undefined;
    if (request.base64) {
      size = Math.round((request.base64.length * 3) / 4);
    } else if (request.text) {
      size = new TextEncoder().encode(request.text).length;
    }

    // Build submission object, only including defined values (Firestore doesn't accept undefined)
    const submission: EvidenceSubmission = {
      id,
      organizationId: request.organizationId,
      epicId: request.epicId,
      taskId: request.taskId,
      featureId: request.featureId,
      criteriaId: request.criteriaId,
      sessionId: request.sessionId,
      type: request.type,
      submittedAt: now,
      version,
      reviewStatus: 'pending_review',
      // Optional fields - only include if defined
      ...(request.title !== undefined && { title: request.title }),
      ...(request.description !== undefined && { description: request.description }),
      ...(request.url !== undefined && { url: request.url }),
      ...(request.base64 !== undefined && { base64: request.base64 }),
      ...(request.text !== undefined && { text: request.text }),
      ...(request.mimeType !== undefined && { mimeType: request.mimeType }),
      ...(size !== undefined && { size }),
      ...(request.testResults !== undefined && { testResults: request.testResults }),
    };

    await this.db.collection('evidenceSubmissions').doc(id).set(submission);

    return submission;
  }

  /**
   * List evidence submissions with filters
   */
  async listEvidenceSubmissions(filters: {
    featureId: string;
    criteriaId?: string;
    reviewStatus?: EvidenceReviewStatus;
  }): Promise<EvidenceSubmission[]> {
    let query: FirebaseFirestore.Query = this.db
      .collection('evidenceSubmissions')
      .where('featureId', '==', filters.featureId);

    if (filters.criteriaId) {
      query = query.where('criteriaId', '==', filters.criteriaId);
    }

    if (filters.reviewStatus) {
      query = query.where('reviewStatus', '==', filters.reviewStatus);
    }

    const snapshot = await query.orderBy('submittedAt', 'desc').get();

    return snapshot.docs.map(doc => doc.data() as EvidenceSubmission);
  }

  /**
   * Get a single evidence submission
   */
  async getEvidenceSubmission(submissionId: string): Promise<EvidenceSubmission | null> {
    const doc = await this.db.collection('evidenceSubmissions').doc(submissionId).get();
    if (!doc.exists) return null;
    return doc.data() as EvidenceSubmission;
  }

  /**
   * Review an evidence submission
   */
  async reviewEvidenceSubmission(
    submissionId: string,
    action: 'approve' | 'reject' | 'request_revision',
    reviewedBy: string,
    comment?: string
  ): Promise<EvidenceSubmission> {
    const ref = this.db.collection('evidenceSubmissions').doc(submissionId);
    const doc = await ref.get();

    if (!doc.exists) {
      throw new Error(`Evidence submission ${submissionId} not found`);
    }

    const statusMap: Record<string, EvidenceReviewStatus> = {
      approve: 'approved',
      reject: 'rejected',
      request_revision: 'needs_revision',
    };

    const now = new Date().toISOString();
    const updates: Partial<EvidenceSubmission> & { reviewComment?: string } = {
      reviewStatus: statusMap[action],
      reviewedAt: now,
      reviewedBy,
    };

    if (comment) {
      updates.reviewComment = comment;
    }

    await ref.update(updates);

    const updated = await ref.get();
    return updated.data() as EvidenceSubmission;
  }

