  /**
   * Create a new Epic with auto-generated ID
   * - If shortKey provided: creates MCP-style "PREFIX-123" ID
   * - Otherwise: creates UUID for UI workflow
   */
  async createEpic(orgId: string, request: CreateEpicRequest, createdBy: string): Promise<Epic> {
    const now = new Date().toISOString();
    let epicId: string;
    let shortKey: string | undefined;
    let sequenceNum: number | undefined;

    // Determine ID format based on shortKey presence
    if (request.shortKey) {
      // MCP-style ID: "PREFIX-123"
      shortKey = request.shortKey.toUpperCase();
      sequenceNum = await this.getNextEpicSequence(orgId, shortKey);
      epicId = `${shortKey}-${sequenceNum}`;
    } else {
      // UI-style ID: UUID
      epicId = uuidv4();
    }

    const epic: Epic = {
      id: epicId,
      title: request.title,
      source: request.source || (request.shortKey ? 'mcp' : 'ui'),
      organizationId: orgId,
      createdBy,
      ownerId: createdBy,
      status: request.status || (request.shortKey ? 'planning' : 'draft'),
      priority: request.priority || 'medium',
      createdAt: now,
      updatedAt: now,
      deletedAt: null, // Soft delete tracking
    };

    // Add MCP-style ID fields if applicable
    if (shortKey !== undefined) {
      epic.shortKey = shortKey;
      epic.sequenceNum = sequenceNum;
    }

    // Add optional fields only if defined
    if (request.description !== undefined) epic.description = request.description;
    if (request.sourceRef !== undefined) epic.sourceRef = request.sourceRef;
    if (request.teamId !== undefined) epic.teamId = request.teamId;
    if (request.ownerId !== undefined) epic.ownerId = request.ownerId;
    if (request.tags !== undefined) epic.tags = request.tags;
    if (request.jiraKey !== undefined) epic.jiraKey = request.jiraKey;
    if (request.jiraSyncEnabled !== undefined) epic.jiraSyncEnabled = request.jiraSyncEnabled;
    if (request.githubRepoUrl !== undefined) epic.githubRepoUrl = request.githubRepoUrl;
    if (request.ciAutoValidate !== undefined) epic.ciAutoValidate = request.ciAutoValidate;
    if (request.ciDeployPreview !== undefined) epic.ciDeployPreview = request.ciDeployPreview;

    await this.db.collection('epics').doc(epicId).set(epic);
    return epic;
  }

  /**
   * Get an Epic by ID (supports both UUID and "PREFIX-123" formats)
   * @param epicId - Epic ID to retrieve
   * @param options - Optional settings
   * @param options.includeDeleted - If true, return soft-deleted epics (for verification)
   */
  async getEpic(epicId: string, options?: { includeDeleted?: boolean }): Promise<Epic | null> {
    const doc = await this.db.collection('epics').doc(epicId).get();
    if (!doc.exists) return null;
    const epic = doc.data() as Epic;
    // Return null if soft-deleted (deletedAt is a timestamp string)
    // Don't filter if deletedAt is null or undefined (not deleted)
    if (epic.deletedAt && !options?.includeDeleted) return null;
    return epic;
  }

  /**
   * Get Epic with computed progress metrics
   */
  async getEpicWithProgress(epicId: string): Promise<{ epic: Epic; progress: EpicProgress } | null> {
    const epic = await this.getEpic(epicId);
    if (!epic) return null;

    const tasks = await this.listTasks(epicId);
    const progress = await this.computeEpicProgress(epicId, tasks);

    return { epic, progress };
  }

  /**
   * List Epics for an organization with optional filters
   */
  async listEpics(orgId: string, filters?: EpicFilters): Promise<Epic[]> {
    let query = this.db.collection('epics')
      .where('organizationId', '==', orgId)
      .where('deletedAt', '==', null); // Filter soft-deleted at database level

    // Apply Firestore-supported filters
    if (filters?.source) {
      query = query.where('source', '==', filters.source);
    }
    if (filters?.status) {
      query = query.where('status', '==', filters.status);
    }
    if (filters?.priority) {
      query = query.where('priority', '==', filters.priority);
    }
    if (filters?.teamId) {
      query = query.where('teamId', '==', filters.teamId);
    }
    if (filters?.createdBy) {
      query = query.where('createdBy', '==', filters.createdBy);
    }

    const snapshot = await query.orderBy('createdAt', 'desc').get();
    let epics = snapshot.docs.map(doc => doc.data() as Epic);

    // Apply in-memory filters
    if (filters?.search) {
      const searchLower = filters.search.toLowerCase();
      epics = epics.filter(e =>
        e.title.toLowerCase().includes(searchLower) ||
        e.description?.toLowerCase().includes(searchLower)
      );
    }
    if (filters?.hasJiraLink === true) {
      epics = epics.filter(e => !!e.jiraKey);
    } else if (filters?.hasJiraLink === false) {
      epics = epics.filter(e => !e.jiraKey);
    }

    return epics;
  }

  /**
   * List Epics with pagination support
   * Returns paginated result with hasMore indicator and nextCursor
   */
  async listEpicsPaginated(orgId: string, filters?: EpicFilters): Promise<PaginatedResult<Epic>> {
    let query = this.db.collection('epics')
      .where('organizationId', '==', orgId)
      .where('deletedAt', '==', null); // Filter soft-deleted at database level

    // Apply Firestore-supported filters
    if (filters?.source) {
      query = query.where('source', '==', filters.source);
    }
    if (filters?.status) {
      query = query.where('status', '==', filters.status);
    }
    if (filters?.priority) {
      query = query.where('priority', '==', filters.priority);
    }
    if (filters?.teamId) {
      query = query.where('teamId', '==', filters.teamId);
    }
    if (filters?.createdBy) {
      query = query.where('createdBy', '==', filters.createdBy);
    }

    query = query.orderBy('createdAt', 'desc');

    // Apply pagination with cursor
    if (filters?.startAfter) {
      const startDoc = await this.db.collection('epics').doc(filters.startAfter).get();
      if (startDoc.exists) {
        query = query.startAfter(startDoc);
      }
    }

    // Default limit to 50 if not specified
    const limit = filters?.limit || 50;
    // Fetch one extra to determine hasMore
    query = query.limit(limit + 1);

    const snapshot = await query.get();
    let epics = snapshot.docs.map(doc => doc.data() as Epic);

    // Apply in-memory filters before pagination check
    if (filters?.search) {
      const searchLower = filters.search.toLowerCase();
      epics = epics.filter(e =>
        e.title.toLowerCase().includes(searchLower) ||
        e.description?.toLowerCase().includes(searchLower)
      );
    }
    if (filters?.hasJiraLink === true) {
      epics = epics.filter(e => !!e.jiraKey);
    } else if (filters?.hasJiraLink === false) {
      epics = epics.filter(e => !e.jiraKey);
    }

    // Determine if there are more results
    const hasMore = epics.length > limit;
    if (hasMore) {
      epics = epics.slice(0, limit);
    }

    // Get nextCursor from last item
    const nextCursor = hasMore && epics.length > 0 ? epics[epics.length - 1].id : undefined;

    return {
      items: epics,
      pagination: {
        hasMore,
        nextCursor,
      },
    };
  }

  /**
   * Get Epic summaries (lightweight, for listing)
   * Optimized to use batch queries instead of N+1 pattern
   */
  async listEpicSummaries(orgId: string, filters?: EpicFilters): Promise<EpicSummary[]> {
    const epics = await this.listEpics(orgId, filters);

    if (epics.length === 0) {
      return [];
    }

    const epicIds = epics.map((e: Epic) => e.id);

    // Batch query all tasks for these epics (Firestore 'in' supports max 10 items)
    const allTasks: EpicTask[] = [];
    for (let i = 0; i < epicIds.length; i += 10) {
      const batch = epicIds.slice(i, i + 10);
      const tasksSnapshot = await this.db.collection('epicTasks')
        .where('epicId', 'in', batch)
        .orderBy('createdAt', 'asc')
        .get();
      allTasks.push(...tasksSnapshot.docs.map(doc => doc.data() as EpicTask));
    }

    // Batch query all features for these epics
    const allFeatures: Feature[] = [];
    for (let i = 0; i < epicIds.length; i += 10) {
      const batch = epicIds.slice(i, i + 10);
      const featuresSnapshot = await this.db.collection('features')
        .where('epicId', 'in', batch)
        .get();
      allFeatures.push(...featuresSnapshot.docs.map(doc => doc.data() as Feature));
    }

    // Group tasks and features by epicId
    const tasksByEpic = new Map<string, EpicTask[]>();
    const featuresByEpic = new Map<string, Feature[]>();

    for (const task of allTasks) {
      if (!tasksByEpic.has(task.epicId)) {
        tasksByEpic.set(task.epicId, []);
      }
      tasksByEpic.get(task.epicId)!.push(task);
    }

    for (const feature of allFeatures) {
      if (!featuresByEpic.has(feature.epicId!)) {
        featuresByEpic.set(feature.epicId!, []);
      }
      featuresByEpic.get(feature.epicId!)!.push(feature);
    }

    // Build summaries with pre-fetched data
    const summaries: EpicSummary[] = [];
    for (const epic of epics) {
      const tasks = tasksByEpic.get(epic.id) || [];
      const features = featuresByEpic.get(epic.id) || [];
      const progress = this.computeEpicProgressFromData(tasks, features);

      summaries.push({
        id: epic.id,
        title: epic.title,
        status: epic.status,
        priority: epic.priority,
        source: epic.source,
        tasksTotal: progress.tasksTotal,
        tasksCompleted: progress.tasksCompleted,
        tasksAvailable: progress.tasksAvailable,
        tasksInProgress: progress.tasksInProgress,
        featuresTotal: progress.featuresTotal,
        featuresCompleted: progress.featuresCompleted,
        criteriaTotal: progress.criteriaTotal,
        criteriaPassed: progress.criteriaPassed,
        createdAt: epic.createdAt,
        updatedAt: epic.updatedAt,
      });
    }

    return summaries;
  }

