  /**
   * Soft delete a Task and all its features
   * Uses batch operations for optimal performance
   *
   * @param taskId - Task ID to soft delete
   * @param deletedBy - User ID or session ID performing the deletion
   */
  async deleteTask(taskId: string, deletedBy?: string): Promise<void> {
    const now = new Date().toISOString();

    // Get all features for this task
    const features = await this.listFeatures(taskId);

    log.info(`Soft deleting task ${taskId}: ${features.length} features`);

    // Batch update all entities
    const batch = this.db.batch();

    // Mark features as deleted
    for (const feature of features) {
      batch.update(this.db.collection('features').doc(feature.id), {
        deletedAt: now,
        deletedBy,
        updatedAt: now
      });
    }

    // Mark task as deleted
    batch.update(this.db.collection('epicTasks').doc(taskId), {
      deletedAt: now,
      deletedBy,
      updatedAt: now
    });

    await batch.commit();
    log.info(`Task ${taskId} and ${features.length} features soft deleted`);
  }

  /**
   * Claim a task for a session
   */
  async claimTask(taskId: string, sessionId: string): Promise<EpicTask | null> {
    const taskRef = this.db.collection('epicTasks').doc(taskId);

    const result = await this.db.runTransaction(async (transaction) => {
      const doc = await transaction.get(taskRef);
      if (!doc.exists) {
        throw new Error(`Task ${taskId} not found`);
      }

      const task = doc.data() as EpicTask;

      // Check if already claimed by another session
      if (task.claimedBySessionId && task.claimedBySessionId !== sessionId) {
        return null; // Already claimed
      }

      const now = new Date().toISOString();
      transaction.update(taskRef, {
        status: 'claimed',
        claimedBySessionId: sessionId,
        claimedAt: now,
        lastActivityAt: now,
        updatedAt: now,
      });

      return {
        ...task,
        status: 'claimed' as TaskStatus,
        claimedBySessionId: sessionId,
        claimedAt: now,
        lastActivityAt: now,
        updatedAt: now,
      };
    });

    return result;
  }

  /**
   * Update task activity timestamp (called when session makes progress)
   */
  async updateTaskActivity(taskId: string): Promise<void> {
    const taskRef = this.db.collection('epicTasks').doc(taskId);
    const now = new Date().toISOString();
    await taskRef.update({
      lastActivityAt: now,
      updatedAt: now,
    });
  }

  /**
   * Release a task claim
   */
  async releaseTask(taskId: string): Promise<EpicTask> {
    const taskRef = this.db.collection('epicTasks').doc(taskId);
    const doc = await taskRef.get();
    if (!doc.exists) {
      throw new Error(`Task ${taskId} not found`);
    }

    const now = new Date().toISOString();
    await taskRef.update({
      status: 'ready',  // Released tasks go back to ready (they were already approved)
      claimedBySessionId: FieldValue.delete(),
      claimedAt: FieldValue.delete(),
      lastActivityAt: FieldValue.delete(),
      updatedAt: now,
    });

    const updated = await taskRef.get();
    return updated.data() as EpicTask;
  }

  /**
   * Force release a task (for stale sessions or manual unlock)
   * Returns the task if released, null if not found or not claimed
   */
  async forceReleaseTask(taskId: string): Promise<EpicTask | null> {
    const taskRef = this.db.collection('epicTasks').doc(taskId);
    const doc = await taskRef.get();
    if (!doc.exists) {
      return null;
    }

    const task = doc.data() as EpicTask;
    if (!task.claimedBySessionId) {
      return null; // Not claimed, nothing to release
    }

    const now = new Date().toISOString();
    await taskRef.update({
      status: 'ready',
      claimedBySessionId: FieldValue.delete(),
      claimedAt: FieldValue.delete(),
      lastActivityAt: FieldValue.delete(),
      updatedAt: now,
    });

    const updated = await taskRef.get();
    return updated.data() as EpicTask;
  }

  /**
   * Check if a task's session is stale (no activity for specified minutes)
   */
  isTaskSessionStale(task: EpicTask, staleMinutes: number = 30): boolean {
    if (!task.claimedBySessionId || !task.lastActivityAt) {
      return false;
    }
    const lastActivity = new Date(task.lastActivityAt).getTime();
    const now = Date.now();
    const staleMs = staleMinutes * 60 * 1000;
    return (now - lastActivity) > staleMs;
  }

  /**
   * Mark a task as completed
   */
  async completeTask(taskId: string): Promise<EpicTask> {
    const now = new Date().toISOString();
    const taskRef = this.db.collection('epicTasks').doc(taskId);

    await taskRef.update({
      status: 'completed',
      completedAt: now,
      updatedAt: now,
    });

    const updated = await taskRef.get();
    return updated.data() as EpicTask;
  }

