  /**
   * Compute Epic progress from tasks and features
   * Optimized: fetches all features for Epic in single query (uses epicId index)
   */
  private async computeEpicProgress(epicId: string, tasks: EpicTask[]): Promise<EpicProgress> {
    const tasksTotal = tasks.length;
    const tasksCompleted = tasks.filter(t => t.status === 'done').length;
    const tasksAvailable = tasks.filter(t => t.status === 'ready').length;
    const tasksInProgress = tasks.filter(t => t.status === 'active').length;

    // Fetch all features for Epic in single query (using denormalized epicId)
    const featuresSnapshot = await this.db.collection('features')
      .where('epicId', '==', epicId)
      .get();
    const allFeatures = featuresSnapshot.docs.map(doc => doc.data() as Feature);

    const featuresTotal = allFeatures.length;
    const featuresCompleted = allFeatures.filter(f => f.status === 'done').length;

    // Compute criteria counts
    let criteriaTotal = 0;
    let criteriaPassed = 0;
    let criteriaFailed = 0;
    let criteriaPending = 0;

    for (const feature of allFeatures) {
      criteriaTotal += feature.acceptanceCriteria.length;
      criteriaPassed += feature.acceptanceCriteria.filter(c => c.status === 'passed').length;
      criteriaFailed += feature.acceptanceCriteria.filter(c => c.status === 'failed').length;
      criteriaPending += feature.acceptanceCriteria.filter(c => c.status === 'pending').length;
    }

    const percentComplete = criteriaTotal > 0 ? Math.round((criteriaPassed / criteriaTotal) * 100) : 0;

    return {
      tasksTotal,
      tasksCompleted,
      tasksAvailable,
      tasksInProgress,
      featuresTotal,
      featuresCompleted,
      criteriaTotal,
      criteriaPassed,
      criteriaFailed,
      criteriaPending,
      percentComplete,
    };
  }

  /**
   * Compute Epic progress from pre-fetched tasks and features
   * Used by listEpicSummaries for batch optimization (no additional queries)
   */
  private computeEpicProgressFromData(tasks: EpicTask[], features: Feature[]): EpicProgress {
    const tasksTotal = tasks.length;
    const tasksCompleted = tasks.filter(t => t.status === 'done').length;
    const tasksAvailable = tasks.filter(t => t.status === 'ready').length;
    const tasksInProgress = tasks.filter(t => t.status === 'active').length;

    const featuresTotal = features.length;
    const featuresCompleted = features.filter(f => f.status === 'done').length;

    // Compute criteria counts
    let criteriaTotal = 0;
    let criteriaPassed = 0;
    let criteriaFailed = 0;
    let criteriaPending = 0;

    for (const feature of features) {
      criteriaTotal += feature.acceptanceCriteria.length;
      criteriaPassed += feature.acceptanceCriteria.filter(c => c.status === 'passed').length;
      criteriaFailed += feature.acceptanceCriteria.filter(c => c.status === 'failed').length;
      criteriaPending += feature.acceptanceCriteria.filter(c => c.status === 'pending').length;
    }

    const percentComplete = criteriaTotal > 0 ? Math.round((criteriaPassed / criteriaTotal) * 100) : 0;

    return {
      tasksTotal,
      tasksCompleted,
      tasksAvailable,
      tasksInProgress,
      featuresTotal,
      featuresCompleted,
      criteriaTotal,
      criteriaPassed,
      criteriaFailed,
      criteriaPending,
      percentComplete,
    };
  }

