/**
 * FirestoreStateManager - Firestore-based session state storage
 *
 * Collection structure:
 * sessions/{sessionId}
 *   ├── (session document fields)
 *   ├── progressLogs/{logId}
 *   └── inputs/{inputId}
 *
 * Unified Epic structure:
 * epics/{epicId}                           - Single collection for all epics (MCP + UI)
 * epicTasks/{taskId}                       - All tasks (with epicId reference)
 * features/{featureId}                     - All features (with taskId + epicId reference)
 */

import { initializeApp, cert, getApps, App } from 'firebase-admin/app';
import { getFirestore, Firestore, FieldValue } from 'firebase-admin/firestore';
import { v4 as uuidv4 } from 'uuid';
import { humanId } from 'human-id';
import type { IStateManager } from './interface.js';

import { createLogger } from '../lib/logger.js';

const log = createLogger('firestore');
import type {
  Session,
  SessionState,
  SessionVisibility,
  SessionMode,
  Feature,
  PendingInput,
  ProgressLog,
  ProgressLogRequest,
  InputRequest,
  Organization,
  OrganizationMember,
  OrganizationInvitation,
  MemberRole,
  Team,
  TeamMember,
  TeamRole,
  TeamStackLayer,
  CreateTeamStackLayerRequest,
  UpdateTeamStackLayerRequest,
  SharedPrompt,
  PromptVisibility,
  Evidence,
  VerificationRecord,
  AddEvidenceRequest,
  VerifyFeatureRequest,
  EvidenceSubmission,
  EvidenceReviewStatus,
  EvidenceType,
  TestResults,
  // Epic types
  Epic,
  EpicTask,
  EpicSummary,
  EpicProgress,
  EpicFilters,
  EpicTaskFilters,
  FeatureFilters,
  CreateEpicRequest,
  UpdateEpicRequest,
  CreateEpicTaskRequest,
  UpdateEpicTaskRequest,
  CreateFeatureRequest,
  UpdateFeatureRequest,
  TaskStatus,
  PaginatedResult,
  Asset,
  ValidationItem,
  EvidenceComment,
} from './types.js';

// Initialize Firebase Admin
function initializeFirebase(): App {
  if (getApps().length > 0) {
    return getApps()[0];
  }

  // For emulator, use project ID from env or default
  const projectId = process.env.GOOGLE_CLOUD_PROJECT || 'session-control-dev';

  // Check if running with emulator
  if (process.env.FIRESTORE_EMULATOR_HOST) {
    log.info(`Connecting to emulator at ${process.env.FIRESTORE_EMULATOR_HOST}`);
    return initializeApp({ projectId });
  }

  // For production, use Application Default Credentials
  // This works on Cloud Run with the default service account
  if (process.env.GOOGLE_APPLICATION_CREDENTIALS) {
    return initializeApp({
      credential: cert(process.env.GOOGLE_APPLICATION_CREDENTIALS),
      projectId,
    });
  }

  // Default: ADC (Application Default Credentials)
  return initializeApp({ projectId });
}

// Singleton Firestore instance with settings applied
let _firestoreInstance: Firestore | null = null;
let _settingsApplied = false;

function getFirestoreInstance(): Firestore {
  if (_firestoreInstance) return _firestoreInstance;

  const app = initializeFirebase();

  // Support named databases via FIRESTORE_DATABASE env var (e.g., "sandbox")
  // Default "(default)" is used if not specified
  const databaseId = process.env.FIRESTORE_DATABASE || '(default)';

  // Validate database ID to catch misconfigurations early
  const validDatabases = ['(default)', 'sandbox'];
  if (!validDatabases.includes(databaseId)) {
    log.warn({ databaseId, validDatabases }, 'Unknown database. Check configuration');
  }

  log.info(`Using database: ${databaseId}`);

  _firestoreInstance = getFirestore(app, databaseId);

  // Enable ignoring undefined properties - must be called before any operations
  // Use a flag to prevent calling settings() multiple times
  if (!_settingsApplied) {
    try {
      _firestoreInstance.settings({ ignoreUndefinedProperties: true });
      _settingsApplied = true;
    } catch {
      // Settings may have already been applied if Firestore was initialized elsewhere
      log.info('Settings already applied, continuing...');
      _settingsApplied = true;
    }
  }

  return _firestoreInstance;
}

export class FirestoreStateManager implements IStateManager {
  private db: Firestore;
  private inputResolvers: Map<string, (response: string, respondedBy: string) => void> = new Map();
  private inputListeners: Map<string, () => void> = new Map();

  constructor() {
    this.db = getFirestoreInstance();
  }

  // ===========================================================================
  // Session Operations
  // ===========================================================================

  async createSession(name?: string, useNameAsId: boolean = false, userId?: string, organizationId?: string): Promise<Session> {
    const sessionName = name || humanId({ separator: '-', capitalize: false });
    const id = useNameAsId ? sessionName : uuidv4();
    const now = new Date().toISOString();

    // If organizationId provided, get default visibility from org settings
    let visibility: SessionVisibility | undefined;
    if (organizationId) {
      const org = await this.getOrganization(organizationId);
      if (org?.settings?.defaultSessionVisibility) {
        visibility = org.settings.defaultSessionVisibility;
      }
    }

    const session: Session = {
      id,
      name: sessionName,
      visibility: visibility || 'private',
      createdAt: now,
      updatedAt: now,
      status: 'active',
      // Only include optional fields if defined (Firestore rejects undefined)
      ...(userId !== undefined && { userId }),
      ...(organizationId !== undefined && { organizationId }),
    };

    await this.db.collection('sessions').doc(id).set(session);

    return session;
  }

  async listSessions(userId?: string, organizationId?: string): Promise<Session[]> {
    // If organizationId provided, filter to org sessions only
    if (organizationId) {
      const snapshot = await this.db.collection('sessions')
        .where('organizationId', '==', organizationId)
        .orderBy('createdAt', 'desc')
        .get();
      return snapshot.docs.map(doc => doc.data() as Session);
    }

    // If userId provided, filter to user's sessions only
    // Also include sessions without userId (legacy/anonymous sessions)
    if (userId) {
      // Firestore doesn't support OR queries easily, so we do two queries
      const [userSessions, legacySessions] = await Promise.all([
        this.db.collection('sessions')
          .where('userId', '==', userId)
          .orderBy('createdAt', 'desc')
          .get(),
        this.db.collection('sessions')
          .where('userId', '==', null)
          .orderBy('createdAt', 'desc')
          .get()
          .catch((err) => {
            log.debug({ err }, 'Legacy sessions query failed (userId field may not exist on old docs)');
            return { docs: [] } as { docs: FirebaseFirestore.QueryDocumentSnapshot[] };
          }),
      ]);

      const sessions = [
        ...userSessions.docs.map(doc => doc.data() as Session),
        ...legacySessions.docs.map(doc => doc.data() as Session),
      ];

      // Sort combined results by createdAt desc
      return sessions.sort((a, b) =>
        new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      );
    }

    const query = this.db.collection('sessions').orderBy('createdAt', 'desc');
    const snapshot = await query.get();
    return snapshot.docs.map(doc => doc.data() as Session);
  }

  async getSession(sessionId: string): Promise<Session | null> {
    const doc = await this.db.collection('sessions').doc(sessionId).get();

    if (!doc.exists) return null;
    return doc.data() as Session;
  }

  async getSessionState(sessionId: string): Promise<SessionState | null> {
    const session = await this.getSession(sessionId);
    if (!session) return null;

    const [progressLogs, pendingInputs] = await Promise.all([
      this.getProgressLogs(sessionId),
      this.getPendingInputs(sessionId),
    ]);

    return { session, progressLogs, pendingInputs };
  }

  async updateSession(
    sessionId: string,
    updates: { visibility?: SessionVisibility; organizationId?: string }
  ): Promise<Session | null> {
    const sessionRef = this.db.collection('sessions').doc(sessionId);
    const doc = await sessionRef.get();

    if (!doc.exists) return null;

    const session = doc.data() as Session;
    const now = new Date().toISOString();

    const updatedSession: Session = {
      ...session,
      updatedAt: now,
    };

    if (updates.visibility !== undefined) {
      updatedSession.visibility = updates.visibility;
    }
    if (updates.organizationId !== undefined) {
      updatedSession.organizationId = updates.organizationId;
    }

    await sessionRef.set(updatedSession);
    return updatedSession;
  }

  async deleteSession(sessionId: string): Promise<boolean> {
    try {
      const sessionRef = this.db.collection('sessions').doc(sessionId);

      // Delete subcollections
      await this.deleteCollection(sessionRef.collection('progressLogs'));
      await this.deleteCollection(sessionRef.collection('inputs'));
      await this.deleteCollection(sessionRef.collection('tasks')); // deprecated but might exist
      await this.deleteCollection(sessionRef.collection('checkpoints')); // deprecated
      await this.deleteCollection(sessionRef.collection('features')); // deprecated but might exist

      // Delete session document
      await sessionRef.delete();

      return true;
    } catch (error) {
      log.error({ err: error }, `Failed to delete session ${sessionId}:`);
      return false;
    }
  }

  async deleteSessions(sessionIds: string[]): Promise<{ deleted: string[]; failed: string[] }> {
    const results = await Promise.all(
      sessionIds.map(async (id) => ({
        id,
        success: await this.deleteSession(id),
      }))
    );

    return {
      deleted: results.filter(r => r.success).map(r => r.id),
      failed: results.filter(r => !r.success).map(r => r.id),
    };
  }

  private async deleteCollection(collectionRef: FirebaseFirestore.CollectionReference): Promise<void> {
    const snapshot = await collectionRef.get();
    const batch = this.db.batch();

    snapshot.docs.forEach(doc => {
      batch.delete(doc.ref);
    });

    if (snapshot.docs.length > 0) {
      await batch.commit();
    }
  }

  // ===========================================================================
  // Feature Operations (Deprecated - Features now in Epic/Task hierarchy)
  // ===========================================================================
  // Session-scoped features are deprecated. Use createFeature/updateFeature with taskId instead.

  // ===========================================================================
  // Progress Log Operations
  // ===========================================================================

  async getProgressLogs(sessionId: string): Promise<ProgressLog[]> {
    const snapshot = await this.db
      .collection('sessions')
      .doc(sessionId)
      .collection('progressLogs')
      .orderBy('createdAt', 'asc')
      .get();

    return snapshot.docs.map(doc => doc.data() as ProgressLog);
  }

  async logProgress(sessionId: string, request: ProgressLogRequest): Promise<ProgressLog> {
    const logId = uuidv4();
    const now = new Date().toISOString();

    const log: ProgressLog = {
      id: logId,
      summary: request.summary,
      createdAt: now,
      ...(request.featureId !== undefined && { featureId: request.featureId }),
    };

    await this.db
      .collection('sessions')
      .doc(sessionId)
      .collection('progressLogs')
      .doc(logId)
      .set(log);

    await this.updateSessionTimestamp(sessionId);

    return log;
  }

  // ===========================================================================
  // Input Request Operations
  // ===========================================================================

  async getPendingInputs(sessionId: string): Promise<PendingInput[]> {
    const snapshot = await this.db
      .collection('sessions')
      .doc(sessionId)
      .collection('inputs')
      .where('respondedAt', '==', null)
      .orderBy('createdAt', 'asc')
      .get();

    return snapshot.docs.map(doc => doc.data() as PendingInput);
  }

  async createInputRequest(sessionId: string, request: InputRequest): Promise<PendingInput> {
    const inputId = uuidv4();
    const now = new Date().toISOString();

    const input: PendingInput = {
      id: inputId,
      prompt: request.prompt,
      urgency: request.urgency || 'normal',
      timeoutMinutes: request.timeoutMinutes || 60,
      createdAt: now,
      ...(request.context !== undefined && { context: request.context }),
      ...(request.options !== undefined && { options: request.options }),
    };

    await this.db
      .collection('sessions')
      .doc(sessionId)
      .collection('inputs')
      .doc(inputId)
      .set(input);

    await this.updateSessionTimestamp(sessionId);

    return input;
  }

  async respondToInput(
    sessionId: string,
    inputId: string,
    response: string,
    respondedBy: string
  ): Promise<PendingInput | null> {
    const inputRef = this.db
      .collection('sessions')
      .doc(sessionId)
      .collection('inputs')
      .doc(inputId);

    const doc = await inputRef.get();
    if (!doc.exists) return null;

    const now = new Date().toISOString();

    const updatedInput: PendingInput = {
      ...(doc.data() as PendingInput),
      response,
      respondedBy,
      respondedAt: now,
    };

    await inputRef.set(updatedInput);
    await this.updateSessionTimestamp(sessionId);

    // Resolve any waiting promises
    const resolver = this.inputResolvers.get(inputId);
    if (resolver) {
      resolver(response, respondedBy);
      this.inputResolvers.delete(inputId);
    }

    return updatedInput;
  }

  async waitForInputResponse(
    sessionId: string,
    inputId: string,
    timeoutMinutes: number
  ): Promise<{ response: string; respondedBy: string } | null> {
    const timeoutMs = timeoutMinutes * 60 * 1000;

    return new Promise((resolve) => {
      // Set up timeout
      const timeout = setTimeout(() => {
        this.inputResolvers.delete(inputId);
        const listener = this.inputListeners.get(inputId);
        if (listener) listener();
        resolve(null);
      }, timeoutMs);

      // Set up resolver
      this.inputResolvers.set(inputId, (response: string, respondedBy: string) => {
        clearTimeout(timeout);
        const listener = this.inputListeners.get(inputId);
        if (listener) listener();
        resolve({ response, respondedBy });
      });

      // Set up Firestore listener
      const unsubscribe = this.db
        .collection('sessions')
        .doc(sessionId)
        .collection('inputs')
        .doc(inputId)
        .onSnapshot((snapshot) => {
          const data = snapshot.data() as PendingInput | undefined;
          if (data?.respondedAt) {
            clearTimeout(timeout);
            unsubscribe();
            this.inputResolvers.delete(inputId);
            this.inputListeners.delete(inputId);
            resolve({
              response: data.response!,
              respondedBy: data.respondedBy!,
            });
          }
        });

      this.inputListeners.set(inputId, unsubscribe);
    });
  }

  // ===========================================================================
  // Evidence & Verification Operations
  // ===========================================================================

  async addEvidence(
    request: AddEvidenceRequest
  ): Promise<{ feature: Feature; evidence: Evidence }> {
    const featureRef = this.db
      .collection('features')
      .doc(request.featureId);

    const doc = await featureRef.get();
    if (!doc.exists) {
      throw new Error(`Feature ${request.featureId} not found`);
    }

    const feature = doc.data() as Feature;
    const criteriaIndex = feature.acceptanceCriteria.findIndex(c => c.id === request.criteriaId);
    if (criteriaIndex === -1) {
      throw new Error(`Criteria ${request.criteriaId} not found in feature ${request.featureId}`);
    }

    const now = new Date().toISOString();
    // Build evidence object, only including defined values (Firestore doesn't accept undefined)
    const evidence: Evidence = {
      id: uuidv4(),
      type: request.evidence.type,
      createdAt: now,
      // Optional fields - only include if defined
      ...(request.evidence.title !== undefined && { title: request.evidence.title }),
      ...(request.evidence.description !== undefined && { description: request.evidence.description }),
      ...(request.evidence.url !== undefined && { url: request.evidence.url }),
      ...(request.evidence.base64 !== undefined && { base64: request.evidence.base64 }),
      ...(request.evidence.text !== undefined && { text: request.evidence.text }),
      ...(request.evidence.mimeType !== undefined && { mimeType: request.evidence.mimeType }),
      ...(request.evidence.size !== undefined && { size: request.evidence.size }),
    };

    // Create a verification record with this evidence
    const verification: VerificationRecord = {
      id: uuidv4(),
      featureId: request.featureId,
      criteriaId: request.criteriaId,
      verificationType: 'manual_check',
      passed: false,
      evidence: [evidence],
      verifiedAt: now,
    };

    const criteria = feature.acceptanceCriteria[criteriaIndex];
    const updatedCriteria = {
      ...criteria,
      verifications: [...(criteria.verifications || []), verification],
    };

    feature.acceptanceCriteria[criteriaIndex] = updatedCriteria;
    await featureRef.update({
      acceptanceCriteria: feature.acceptanceCriteria,
      updatedAt: now,
    });

    return { feature, evidence };
  }

  async verifyFeature(
    request: VerifyFeatureRequest
  ): Promise<{ feature: Feature; verification: VerificationRecord }> {
    const featureRef = this.db
      .collection('features')
      .doc(request.featureId);

    const doc = await featureRef.get();
    if (!doc.exists) {
      throw new Error(`Feature ${request.featureId} not found`);
    }

    const feature = doc.data() as Feature;
    const criteriaIndex = feature.acceptanceCriteria.findIndex(c => c.id === request.criteriaId);
    if (criteriaIndex === -1) {
      throw new Error(`Criteria ${request.criteriaId} not found in feature ${request.featureId}`);
    }

    const now = new Date().toISOString();

    // Create evidence if provided, filtering out undefined values (Firestore doesn't accept undefined)
    const evidenceList: Evidence[] = (request.evidence || []).map(e => ({
      id: uuidv4(),
      type: e.type,
      createdAt: now,
      ...(e.title !== undefined && { title: e.title }),
      ...(e.description !== undefined && { description: e.description }),
      ...(e.url !== undefined && { url: e.url }),
      ...(e.base64 !== undefined && { base64: e.base64 }),
      ...(e.text !== undefined && { text: e.text }),
      ...(e.mimeType !== undefined && { mimeType: e.mimeType }),
      ...(e.size !== undefined && { size: e.size }),
    }));

    // Create verification record
    const verification: VerificationRecord = {
      id: uuidv4(),
      featureId: request.featureId,
      criteriaId: request.criteriaId,
      verificationType: request.verificationType,
      passed: request.passed,
      verifiedAt: now,
      ...(request.notes !== undefined && { notes: request.notes }),
      ...(evidenceList.length > 0 && { evidence: evidenceList }),
    };

    // Update criteria status if verification passed
    const criteria = feature.acceptanceCriteria[criteriaIndex];
    const updatedCriteria = {
      ...criteria,
      status: request.passed ? ('passed' as const) : criteria.status,
      verifications: [...(criteria.verifications || []), verification],
    };

    feature.acceptanceCriteria[criteriaIndex] = updatedCriteria;
    await featureRef.update({
      acceptanceCriteria: feature.acceptanceCriteria,
      updatedAt: now,
    });

    return { feature, verification };
  }

  async getVerifications(
    featureId: string
  ): Promise<VerificationRecord[]> {
    const feature = await this.db
      .collection('features')
      .doc(featureId)
      .get();

    if (!feature.exists) return [];

    const featureData = feature.data() as Feature;
    const allVerifications: VerificationRecord[] = [];

    for (const criteria of featureData.acceptanceCriteria) {
      if (criteria.verifications) {
        allVerifications.push(...criteria.verifications);
      }
    }

    return allVerifications;
  }

  async getCriterionVerifications(
    featureId: string,
    criteriaId: string
  ): Promise<VerificationRecord[]> {
    const feature = await this.db
      .collection('features')
      .doc(featureId)
      .get();

    if (!feature.exists) return [];

    const featureData = feature.data() as Feature;
    const criteria = featureData.acceptanceCriteria.find(c => c.id === criteriaId);

    return criteria?.verifications || [];
  }

  // ===========================================================================
  // Evidence Submission Operations (Review Workflow)
  // ===========================================================================

  /**
   * Submit evidence for review (creates EvidenceSubmission)
   */
  async submitEvidence(request: {
    organizationId: string;
    epicId: string;
    taskId: string;
    featureId: string;
    criteriaId: string;
    sessionId: string;
    type: EvidenceType;
    title?: string;
    description?: string;
    url?: string;
    base64?: string;
    text?: string;
    mimeType?: string;
    testResults?: TestResults;
  }): Promise<EvidenceSubmission> {
    const now = new Date().toISOString();
    const id = uuidv4();

    // Get current version count for this criteria
    const existingSubmissions = await this.db
      .collection('evidenceSubmissions')
      .where('criteriaId', '==', request.criteriaId)
      .get();

    const version = existingSubmissions.size + 1;

    // Calculate size if base64 is provided
    let size: number | undefined;
    if (request.base64) {
      size = Math.round((request.base64.length * 3) / 4);
    } else if (request.text) {
      size = new TextEncoder().encode(request.text).length;
    }

    // Build submission object, only including defined values (Firestore doesn't accept undefined)
    const submission: EvidenceSubmission = {
      id,
      organizationId: request.organizationId,
      epicId: request.epicId,
      taskId: request.taskId,
      featureId: request.featureId,
      criteriaId: request.criteriaId,
      sessionId: request.sessionId,
      type: request.type,
      submittedAt: now,
      version,
      reviewStatus: 'pending_review',
      // Optional fields - only include if defined
      ...(request.title !== undefined && { title: request.title }),
      ...(request.description !== undefined && { description: request.description }),
      ...(request.url !== undefined && { url: request.url }),
      ...(request.base64 !== undefined && { base64: request.base64 }),
      ...(request.text !== undefined && { text: request.text }),
      ...(request.mimeType !== undefined && { mimeType: request.mimeType }),
      ...(size !== undefined && { size }),
      ...(request.testResults !== undefined && { testResults: request.testResults }),
    };

    await this.db.collection('evidenceSubmissions').doc(id).set(submission);

    return submission;
  }

  /**
   * List evidence submissions with filters
   */
  async listEvidenceSubmissions(filters: {
    featureId: string;
    criteriaId?: string;
    reviewStatus?: EvidenceReviewStatus;
  }): Promise<EvidenceSubmission[]> {
    let query: FirebaseFirestore.Query = this.db
      .collection('evidenceSubmissions')
      .where('featureId', '==', filters.featureId);

    if (filters.criteriaId) {
      query = query.where('criteriaId', '==', filters.criteriaId);
    }

    if (filters.reviewStatus) {
      query = query.where('reviewStatus', '==', filters.reviewStatus);
    }

    const snapshot = await query.orderBy('submittedAt', 'desc').get();

    return snapshot.docs.map(doc => doc.data() as EvidenceSubmission);
  }

  /**
   * Get a single evidence submission
   */
  async getEvidenceSubmission(submissionId: string): Promise<EvidenceSubmission | null> {
    const doc = await this.db.collection('evidenceSubmissions').doc(submissionId).get();
    if (!doc.exists) return null;
    return doc.data() as EvidenceSubmission;
  }

  /**
   * Review an evidence submission
   */
  async reviewEvidenceSubmission(
    submissionId: string,
    action: 'approve' | 'reject' | 'request_revision',
    reviewedBy: string,
    comment?: string
  ): Promise<EvidenceSubmission> {
    const ref = this.db.collection('evidenceSubmissions').doc(submissionId);
    const doc = await ref.get();

    if (!doc.exists) {
      throw new Error(`Evidence submission ${submissionId} not found`);
    }

    const statusMap: Record<string, EvidenceReviewStatus> = {
      approve: 'approved',
      reject: 'rejected',
      request_revision: 'needs_revision',
    };

    const now = new Date().toISOString();
    const updates: Partial<EvidenceSubmission> & { reviewComment?: string } = {
      reviewStatus: statusMap[action],
      reviewedAt: now,
      reviewedBy,
    };

    if (comment) {
      updates.reviewComment = comment;
    }

    await ref.update(updates);

    const updated = await ref.get();
    return updated.data() as EvidenceSubmission;
  }

