  async acceptInvitation(inviteId: string, userId: string, userEmail: string): Promise<OrganizationInvitation> {
    const inviteRef = this.db.collection('invitations').doc(inviteId);
    const doc = await inviteRef.get();
    if (!doc.exists) {
      throw new Error(`Invitation ${inviteId} not found`);
    }

    const invitation = doc.data() as OrganizationInvitation;
    if (invitation.email !== userEmail) {
      throw new Error('Invitation email does not match user email');
    }

    const now = new Date().toISOString();

    await inviteRef.update({
      status: 'accepted',
      acceptedBy: userId,
      acceptedAt: now,
    });

    await this.addOrganizationMember(invitation.organizationId, userId, invitation.role);

    const updated = await inviteRef.get();
    return updated.data() as OrganizationInvitation;
  }

