/**
 * EpicProgress - Computed progress metrics
 * Not stored, calculated on demand
 */
export interface EpicProgress {
  tasksTotal: number;
  tasksCompleted: number;
  tasksAvailable: number;           // Available for claiming (MCP)
  tasksInProgress: number;

  featuresTotal: number;
  featuresCompleted: number;

  criteriaTotal: number;
  criteriaPassed: number;
  criteriaFailed: number;
  criteriaPending: number;

  percentComplete: number;          // Based on criteria passed
