export function getRepoFullName(connection: RepoConnection): string {
  const provider = connection.provider ?? 'github';
  if (provider === 'bitbucket') {
    if (!connection.bitbucketRepoFullName) {
      throw new Error(`RepoConnection "${connection.id}" (bitbucket) missing bitbucketRepoFullName`);
    }
    return connection.bitbucketRepoFullName;
  }
  if (!connection.githubRepoFullName) {
    throw new Error(`RepoConnection "${connection.id}" (github) missing githubRepoFullName`);
  }
  return connection.githubRepoFullName;
}

export function getRepoId(connection: RepoConnection): string | number {
  const provider = connection.provider ?? 'github';
  if (provider === 'bitbucket') {
    if (!connection.bitbucketRepoUuid) {
      throw new Error(`RepoConnection "${connection.id}" (bitbucket) missing bitbucketRepoUuid`);
    }
    return connection.bitbucketRepoUuid;
  }
  if (!connection.githubRepoId) {
    throw new Error(`RepoConnection "${connection.id}" (github) missing githubRepoId`);
  }
  return connection.githubRepoId;
}

export function getProviderType(connection: RepoConnection): GitProviderType {
  return connection.provider ?? 'github';
}

