  submissionId?: string;           // Link to EvidenceSubmission that triggered this
}

/**
 * StatusTransition - Record of a status change
 *
 * Tracks all status transitions for audit and debugging.
 */
export interface StatusTransition {
  from: string;                    // Previous status
  to: string;                      // New status
  timestamp: string;               // ISO timestamp
  actor: string;                   // User/session ID that triggered
  actorType: 'ai' | 'human';       // Whether AI or human triggered
  reason?: string;                 // Why the transition happened
  cascadedFrom?: {                 // If this was triggered by a child entity
    entityType: 'feature' | 'task';
    entityId: string;
  };
}

/**
 * ReadinessCheckItem - Individual readiness criterion
 */
export interface ReadinessCheckItem {
  id: string;
  label: string;                   // e.g., "Has at least one feature"
  description?: string;            // Detailed explanation
  passed: boolean;                 // Whether this check passes
  details?: string;                // Additional context (e.g., "3 of 5 criteria defined")
}

/**
 * ReadinessChecklist - Checklist for determining if entity is ready
 *
 * Used to validate that a Task or Feature has complete requirements
 * before it can transition from draft to ready.
 */
export interface ReadinessChecklist {
  items: ReadinessCheckItem[];
  isReady: boolean;                // True if all items pass
  completedCount: number;          // Number of items that pass
  totalCount: number;              // Total number of items
}

/**
 * WorkflowSubmissionMetadata - Type-specific metadata for workflow submissions
 *
 * Stored in EvidenceSubmission.workflowMetadata for workflow-type submissions.
 */
export interface WorkflowSubmissionMetadata {
  // For feature_suggestion
  suggestedFeature?: {
    title: string;
    description?: string;
    suggestedCriteria?: Array<{
      description: string;
      validationType?: string;
    }>;
  };

  // For criteria_refinement
  criteriaRefinement?: {
    originalText: string;
    suggestedText: string;
    rationale: string;
  };

  // For readiness_check
  readinessCheck?: {
    checklist: ReadinessChecklist;
    summary: string;               // AI-generated summary of what's ready
  };

  // For completion_review
  completionReview?: {
    summary: string;               // AI summary of completed work
    featureIds: string[];          // Features included in this review
    evidenceIds: string[];         // Evidence submissions to review
  };
}

// =============================================================================
// TEST RESULTS TYPES (for tangible test evidence)
// =============================================================================

/**
 * TestResults - Structured test output for tangible evidence
 *
 * Distinguishes between new tests added for a feature vs pre-existing tests,
 * making verification evidence more meaningful.
 */
export interface TestResults {
  framework?: string;                    // 'vitest', 'jest', 'mocha', etc.
  newTests: {
    count: number;
    names?: string[];                    // Optional: names of new tests added
  };
  existingTests: {
    count: number;
    passed: number;
    failed: number;
  };
  summary: {
    total: number;
    passed: number;
    failed: number;
    skipped: number;
    duration?: number;                   // milliseconds
  };
}

// =============================================================================
// COMMIT & QUALITY GATES TYPES (for task completion tracking)
// =============================================================================

/**
 * TaskCommit - Git commit associated with a task completion
 */
export interface TaskCommit {
  sha: string;                           // Full or short commit SHA
  message?: string;                      // Commit message
  filesChanged?: string[];               // List of files changed
}

/**
 * QualityGateResult - Result of a single quality check
 */
export interface QualityGateResult {
  passed: boolean;                       // Based on exit_code: 0=passed, non-zero=failed
  exitCode: number;                      // Actual exit code from command
}

/**
 * LintResult - Lint quality gate result
 */
export interface LintResult extends QualityGateResult {
  errors?: number;
  warnings?: number;
}

/**
 * TypecheckResult - TypeScript/type check quality gate result
 */
export interface TypecheckResult extends QualityGateResult {
  errors?: number;
}

/**
 * TestsResult - Test quality gate result with detailed stats
 */
export interface TestsResult extends QualityGateResult {
  total?: number;                        // Total number of tests
  passedCount?: number;                  // Tests passed
  failedCount?: number;                  // Tests failed
  skippedCount?: number;                 // Tests skipped
  durationMs?: number;                   // Test duration in milliseconds
  failures?: string[];                   // Failed test names/locations
  snapshotsUpdated?: number;             // Snapshots updated (requires review!)
  snapshotsFailed?: number;              // Snapshot tests failed
}

/**
 * QualityGates - Collection of quality gate results
 */
export interface QualityGates {
  lint?: LintResult;
  typecheck?: TypecheckResult;
  tests?: TestsResult;
  build?: QualityGateResult;
}

/**
 * Determine if quality gates require human review
 * (e.g., snapshots were updated)
 */
export function qualityGatesRequireReview(gates: QualityGates): { required: boolean; reasons: string[] } {
  const reasons: string[] = [];

  if (gates.tests?.snapshotsUpdated && gates.tests.snapshotsUpdated > 0) {
    reasons.push(`${gates.tests.snapshotsUpdated} snapshot(s) updated`);
  }

  return {
    required: reasons.length > 0,
    reasons,
  };
}

// =============================================================================
// EVIDENCE TYPES (for verification proof)
// =============================================================================

/**
 * Evidence - Proof that an acceptance criterion has been met
 *
 * Supports multiple content types:
 * - base64: Inline small images (< 1MB)
 * - url: Cloud Storage URL for large files
 * - text: Log output, test results, descriptions
 */
export interface Evidence {
  id: string;
  type: EvidenceType;
  title?: string;
  description?: string;

  // Content (one of these should be provided)
  url?: string;           // Cloud Storage URL or external link
  base64?: string;        // Inline base64 encoded content
  text?: string;          // Plain text content (logs, test output)

  // Metadata
  mimeType?: string;      // e.g., 'image/png', 'text/plain'
  size?: number;          // Size in bytes
  createdAt: string;

  // Structured test results (for tangible test evidence)
  testResults?: TestResults;
}

/**
 * VerificationRecord - Record of a verification attempt
 *
 * Created when verify_feature is called. Links evidence to specific
 * acceptance criteria with metadata about how verification was performed.
 */
export interface VerificationRecord {
  id: string;
  featureId: string;
  criteriaId: string;
  verificationType: VerificationType;
  passed: boolean;
  notes?: string;
  evidence?: Evidence[];   // Evidence attached to this verification
  verifiedAt: string;
  verifiedBy?: string;     // Agent or user who performed verification
}

// =============================================================================
// EXPECTED EVIDENCE (defined by squad members)
// =============================================================================

/**
 * ExpectedEvidence - What evidence is required for an acceptance criterion
 *
 * Squad members define expected evidence types and optionally attach
 * reference examples (mockups, expected outputs) for comparison.
 */
export interface ExpectedEvidence {
  id: string;
  type: EvidenceType;
  description: string;              // What this evidence should show
  required: boolean;                // Is this evidence mandatory?

  // Reference example (optional)
  referenceUrl?: string;            // GCS URL to expected screenshot/output
  referenceBase64?: string;         // Inline reference for small images
  referenceText?: string;           // Expected text output pattern

  // Comparison settings (for visual evidence)
  diffThreshold?: number;           // Max acceptable diff % (e.g., 0.05 = 5%)
  ignoreRegions?: Array<{           // Regions to ignore in comparison
    x: number;
    y: number;
    width: number;
    height: number;
  }>;

  // Codebase artifact path (for ticket integration — TICKET-1 epic)
  codebaseArtifactPath?: string;    // Relative path to source/test file that satisfies this criterion
}

/**
 * EvidenceSubmission - A single evidence submission with review workflow
 *
 * Extends Evidence with review status and feedback capabilities.
 * Stored in a separate collection for querying across features.
 */
export interface EvidenceSubmission {
  id: string;

  // Linking
  organizationId: string;
  epicId: string;
  taskId: string;
  featureId: string;
  criteriaId: string;
  sessionId: string;                // Which session submitted this

  // For workflow submissions, link to the target entity
  targetEntityType?: 'epic' | 'task' | 'feature';  // Entity this submission is about
  targetEntityId?: string;          // ID of target entity (may differ from featureId)

  // Evidence content (same as Evidence)
  type: EvidenceType;
  title?: string;
  description?: string;
  url?: string;
  base64?: string;
  text?: string;
  mimeType?: string;
  size?: number;
  testResults?: TestResults;

  // Workflow submission metadata (for readiness_check, feature_suggestion, etc.)
  workflowMetadata?: WorkflowSubmissionMetadata;

  // Submission metadata
  submittedAt: string;
  submittedBy?: string;             // Agent or user who submitted
  version: number;                  // Increments on resubmission

  // Review workflow
  reviewStatus: EvidenceReviewStatus;
  reviewedAt?: string;
  reviewedBy?: string;
  reviewComment?: string;             // Optional feedback from reviewer

  // Comparison results (for visual evidence)
  comparisonResult?: {
    diffPercentage: number;
    diffPixels: number;
    diffImageUrl?: string;          // GCS URL to diff image
    passed: boolean;                // Within threshold?
  };

  // Annotations (drawing overlays on screenshots)
  annotations?: EvidenceAnnotation[];
}

/**
 * EvidenceAnnotation - Drawing/markup on a screenshot
 *
 * Stores vector annotation data that can be rendered as an overlay.
 */
export interface EvidenceAnnotation {
  id: string;
  type: 'rectangle' | 'circle' | 'arrow' | 'freehand' | 'text';
  createdBy: string;
  createdAt: string;

  // Common properties
  color: string;                    // Hex color (e.g., "#FF0000")
  strokeWidth?: number;

  // Type-specific data
  data: {
    // For rectangle/circle
    x?: number;
    y?: number;
    width?: number;
    height?: number;

    // For arrow
    startX?: number;
    startY?: number;
    endX?: number;
    endY?: number;

    // For freehand
    points?: Array<{ x: number; y: number }>;

    // For text
    text?: string;
    fontSize?: number;
  };
}

/**
 * EvidenceComment - Comment thread on evidence
 */
export interface EvidenceComment {
  id: string;
  evidenceId: string;               // EvidenceSubmission ID
  parentId?: string;                // For threaded replies

  content: string;
  createdBy: string;
  createdAt: string;
  updatedAt?: string;

  // Position reference (for pinned comments on images)
  position?: {
    x: number;                      // % from left (0-100)
    y: number;                      // % from top (0-100)
  };

  // Resolution tracking
  resolved?: boolean;
  resolvedAt?: string;
  resolvedBy?: string;
}

/**
 * EvidenceReviewAction - Action taken during evidence review
 */
export interface EvidenceReviewAction {
  action: 'approve' | 'reject' | 'request_revision';
  comment?: string;
  annotations?: EvidenceAnnotation[];  // Annotations added with the action
}

// =============================================================================
// CORE TYPES (Aligned with Anthropic Two-Agent Pattern)
// =============================================================================

export type SessionVisibility = 'private' | 'organization' | 'public';

export interface Session {
  id: string;
  name: string;
  userId?: string;           // Owner of this session (from API key auth)
  organizationId?: string;   // Organization this session belongs to
  visibility?: SessionVisibility;  // Session visibility (defaults to organization setting or 'private')
  createdAt: string;
  updatedAt: string;
  status: 'active' | 'paused' | 'completed';

  // Epic linking (optional - session may or may not be linked to an Epic)
  epicId?: string;           // Epic this session is working on (e.g., "DATA-23")
  taskId?: string;           // Current task being worked on within the Epic
  mode?: SessionMode;        // Capacity: develop, validate, or manage
}

export interface AcceptanceCriteria {
  id: string;
  description: string;
  status: CriteriaStatus;
  validationType?: ValidationCriteriaType;  // Optional validation type for UI workflow
  lastValidatedAt?: string;
  validatedBy?: string;                     // Agent or user who validated
  notes?: string;
  verifications?: VerificationRecord[];     // History of verification attempts

  // Expected evidence (defined by squad members)
  expectedEvidence?: ExpectedEvidence[];    // What evidence is required for this criterion
}

export interface Checkpoint {
  id: string;
  summary: string;
  artifacts?: string[];
  state?: Record<string, unknown>;
  createdAt: string;
}

/**
 * Feature - THE primary unit of work
 *
 * Features always belong to a Task within an Epic (Epic -> Task -> Feature).
 * Sessions must link to an Epic before creating features.
 */
export interface Feature {
  id: string;
  taskId: string;               // Required - parent task
  epicId: string;               // Required - parent epic (denormalized for queries)

  title: string;
  description?: string;
  status: FeatureStatus;        // draft | ready | active | review | done | blocked

  acceptanceCriteria: AcceptanceCriteria[];

  // Parallel execution fields
  assignedAgent?: AgentType;    // Agent type assigned to work on this feature
  dependsOn?: string[];         // Feature IDs this feature depends on
  canParallelize?: boolean;     // Can run in parallel with other features
  estimatedComplexity?: TaskComplexity;  // Complexity estimate for planning

  // Execution tracking
  startedAt?: string;           // When work started on this feature
  completedAt?: string;         // When feature was completed
  executedBy?: string;          // Subagent session ID that executed this

  // Completion details
  result?: string;              // Summary of what was done
  artifacts?: string[];         // Files created/modified
  commit?: TaskCommit;          // Git commit associated with completion

  // Soft delete
  deletedAt?: string | null;
  deletedBy?: string | null;           // User ID or session ID who deleted
  qualityGates?: QualityGates;  // Results of quality checks
  requiresReview?: boolean;     // True if human review needed (e.g., snapshots)
  reviewReasons?: string[];     // Why review is required

