export type GraphBuildJobStatus = 'queued' | 'cloning' | 'building' | 'syncing_issues' | 'completed' | 'failed';

export interface GraphBuildJob {
  id: string;
  orgId: string;
  repoConnectionId: string;
  repoFullName: string;               // "owner/repo"
  status: GraphBuildJobStatus;
  triggeredBy: 'webhook' | 'manual';
  commitSha: string;
  branch: string;
  startedAt?: string;
  completedAt?: string;
