export const toolNames = definitions.map(d => d.name);

export async function handle(
  name: string,
  args: Record<string, unknown>,
  deps: ToolDependencies
): Promise<ToolResponse> {
  const { stateManager, wsHandler, sessionId } = deps;

  // Read-only tools can work without a session by using the org-scoped MCP endpoint's orgId
  const readOnlyTools = ['list_epics', 'get_epic'];
  const session = sessionId ? await stateManager.getSession(sessionId) : null;

  const orgId = session?.organizationId || getCurrentOrgId();
  if (!orgId && !readOnlyTools.includes(name)) {
    return errorResponse(
      'no_organization',
      'No organization context. Either start a session (session_init) or use the org-scoped MCP endpoint.'
    );
  }

  const userId = getCurrentUserId() || 'anonymous';

  switch (name) {
    case 'create_epic': {
      const title = args.title as string;
      // Sanitize shortKey: remove non-alphabetic chars before validation
      const rawShortKey = args.short_key as string;
      const shortKey = rawShortKey.toUpperCase().replace(/[^A-Z]/g, '');
      const description = args.description as string | undefined;
      const priority = args.priority as 'low' | 'medium' | 'high' | 'critical' | undefined;
      const tags = args.tags as string[] | undefined;

      // Validate shortKey format (after sanitization)
      if (!/^[A-Z]{2,10}$/.test(shortKey)) {
        return errorResponse(
          'invalid_short_key',
          'short_key must be 2-10 uppercase letters (e.g., "AUTH", "DATA")'
        );
      }

      if (!orgId) {
        return errorResponse('no_organization', 'Organization context required to create an epic.');
      }

      try {
        const epic = await stateManager.createEpic(orgId, {
          title,
          shortKey,
          description,
          priority,
          tags,
          source: 'mcp',
        }, userId);

        // Auto-link session to the new Epic
        if (sessionId && session) {
          await stateManager.linkSessionToEpic(sessionId, epic.id, session.mode || 'develop');
        }

        // Broadcast event
        wsHandler.broadcast(sessionId, 'epic:created', epic);

        return jsonResponse({
          success: true,
          epic_id: epic.id,
          title: epic.title,
          status: epic.status,
          message: `Epic ${epic.id} created and session linked. Use create_task to add tasks.`,
        });
      } catch (error) {
        return errorResponse(
          'create_failed',
          error instanceof Error ? error.message : 'Failed to create Epic'
        );
      }
    }

    case 'list_epics': {
      if (!orgId) {
        return errorResponse(
          'no_organization',
          'No organization context. Either start a session (session_init) or use the org-scoped MCP endpoint.'
        );
      }
      const status = args.status as EpicStatus | undefined;

      try {
        // Use paginated query with limit to prevent context overflow
        const result = await stateManager.listEpicSummariesPaginated(orgId, {
          status,
          limit: 50,
        });

        return jsonResponse({
          epics: result.items.map(e => ({
            id: e.id,
            title: e.title,
            status: e.status,
            source: e.source,
            tasks: {
              total: e.tasksTotal,
              available: e.tasksAvailable,
              in_progress: e.tasksInProgress,
              completed: e.tasksCompleted,
            },
            created_at: e.createdAt,
          })),
          total: result.items.length,
          pagination: {
            has_more: result.pagination.hasMore,
            next_cursor: result.pagination.nextCursor,
            hint: result.pagination.hasMore
              ? 'Showing first 50 epics. Full pagination support with limit/cursor parameters coming soon. Use status filter to narrow results.'
              : undefined,
          },
          filters: { status },
        });
      } catch (error) {
        return errorResponse(
          'list_failed',
          error instanceof Error ? error.message : 'Failed to list Epics'
        );
      }
    }

    case 'get_epic': {
      const epicId = args.epic_id as string;

      try {
        const epic = await stateManager.getEpic(epicId);
        if (!epic) {
          return errorResponse('not_found', `Epic ${epicId} not found`);
        }

        const tasks = await stateManager.listTasks(epicId);

        // Batch get feature counts for all tasks (avoids N+1 queries)
        const taskIds = tasks.map((t) => t.id);
        const featuresByTask = await stateManager.listFeaturesForTasks(taskIds);

        const tasksWithFeatureCounts = tasks.map((t) => {
          const features = featuresByTask.get(t.id) || [];
          return {
            id: t.id,
            title: t.title,
            description: t.description,
            status: t.status,
            claimed_by_session: t.claimedBySessionId,
            depends_on: t.dependsOn,
            complexity: t.estimatedComplexity,
            features_count: features.length,
          };
        });

        return jsonResponse({
          id: epic.id,
          title: epic.title,
          description: epic.description,
          status: epic.status,
          priority: epic.priority,
          source: epic.source,
          source_ref: epic.sourceRef,
          tags: epic.tags,
          created_by: epic.createdBy,
          owner_id: epic.ownerId,
          created_at: epic.createdAt,
          updated_at: epic.updatedAt,
          tasks: tasksWithFeatureCounts,
        });
      } catch (error) {
        return errorResponse(
          'get_failed',
          error instanceof Error ? error.message : 'Failed to get Epic'
        );
      }
    }

    case 'update_epic': {
      const epicId = args.epic_id as string;
      const updates: Record<string, unknown> = {};

      if (args.title) updates.title = args.title;
      if (args.description) updates.description = args.description;
      if (args.status) updates.status = args.status;
      if (args.priority) updates.priority = args.priority;

      if (Object.keys(updates).length === 0) {
        return errorResponse('no_updates', 'No updates provided');
      }

      try {
        const epic = await stateManager.updateEpic(epicId, updates as Parameters<typeof stateManager.updateEpic>[1]);

        wsHandler.broadcast(sessionId, 'epic:updated', epic);

        return jsonResponse({
          success: true,
          epic_id: epic.id,
          updated: Object.keys(updates),
        });
      } catch (error) {
        return errorResponse(
          'update_failed',
          error instanceof Error ? error.message : 'Failed to update Epic'
        );
      }
    }

    case 'create_task': {
      const epicId = args.epic_id as string;
      const title = args.title as string;
      const description = args.description as string | undefined;
      const dependsOn = args.depends_on as string[] | undefined;
      const complexity = args.complexity as TaskComplexity | undefined;
      const tags = args.tags as string[] | undefined;

      // Verify epic exists
      const epic = await stateManager.getEpic(epicId);
      if (!epic) {
        return errorResponse('epic_not_found', `Epic ${epicId} not found`);
      }

      try {
        const task = await stateManager.createTask({
          epicId,
          title,
          description,
          dependsOn,
          estimatedComplexity: complexity,
          tags,
        });

        wsHandler.broadcast(sessionId, 'epic:task:created', { epicId, task });

        return jsonResponse({
          success: true,
          task_id: task.id,
          epic_id: epicId,
          title: task.title,
          status: task.status,
          message: 'Task created. Use claim_task to start working on it.',
        });
      } catch (error) {
        return errorResponse(
          'create_failed',
          error instanceof Error ? error.message : 'Failed to create task'
        );
      }
    }

    case 'claim_task': {
      const taskId = args.task_id as string;

      try {
        // Check if task can be claimed (status gate)
        const claimCheck = await canClaimTask(stateManager, taskId);
        if (!claimCheck.canClaim) {
          // Provide helpful error with next action
          if (claimCheck.task?.status === 'draft') {
            return workflowErrorResponse(
              'status_gate_blocked',
              claimCheck.reason || 'Task cannot be claimed',
              {
                tool: 'check_readiness',
                description: 'Check task readiness criteria',
                example_params: { task_id: taskId },
              },
              {
                current_status: claimCheck.task.status,
                required_status: 'ready',
                hint: 'A human must approve the requirements and mark the task as "ready" before AI can claim it.',
              }
            );
          }
          return errorResponse(
            'claim_blocked',
            claimCheck.reason || 'Task cannot be claimed'
          );
        }

        const task = await stateManager.claimTask(taskId, sessionId);

        if (!task) {
          return errorResponse(
            'already_claimed',
            'Task is already claimed by another session. Use list_epics or get_epic to see available tasks.'
          );
        }

        // Also set this as the session's current task
        await stateManager.setSessionTask(sessionId, taskId);

        // Update task status to active when claimed
        await stateManager.updateTask(taskId, { status: 'active' });

        wsHandler.broadcast(sessionId, 'epic:task:claimed', { taskId, claimedBy: sessionId });

        return jsonResponse({
          success: true,
          task_id: task.id,
          title: task.title,
          status: 'active',
          message: 'Task claimed and now active! Create features with update_features to track deliverables.',
        });
      } catch (error) {
        return errorResponse(
          'claim_failed',
          error instanceof Error ? error.message : 'Failed to claim task'
        );
      }
    }

    case 'release_task': {
      const taskId = args.task_id as string;

      try {
        const task = await stateManager.getTask(taskId);
        if (!task) {
          return errorResponse('not_found', `Task ${taskId} not found`);
        }

        // Only allow releasing if this session claimed it
        if (task.claimedBySessionId !== sessionId) {
          return errorResponse(
            'not_owner',
            'Cannot release a task claimed by another session'
          );
        }

        const released = await stateManager.releaseTask(taskId);

        wsHandler.broadcast(sessionId, 'epic:task:updated', { taskId, status: 'ready' });

        return jsonResponse({
          success: true,
          task_id: released.id,
          status: released.status,
          message: 'Task released and available for other sessions.',
        });
      } catch (error) {
        return errorResponse(
          'release_failed',
          error instanceof Error ? error.message : 'Failed to release task'
        );
      }
    }

    case 'force_release_task': {
      const taskId = args.task_id as string;

      try {
        const task = await stateManager.getTask(taskId);
        if (!task) {
          return errorResponse('not_found', `Task ${taskId} not found`);
        }

        if (!task.claimedBySessionId) {
          return errorResponse('not_claimed', 'Task is not claimed by any session');
        }

        const previousSessionId = task.claimedBySessionId;
        const released = await stateManager.forceReleaseTask(taskId);

        if (!released) {
          return errorResponse('release_failed', 'Failed to release task');
        }

        wsHandler.broadcast(sessionId, 'epic:task:updated', { taskId, status: 'ready' });

        return jsonResponse({
          success: true,
          task_id: released.id,
          status: released.status,
          previous_session_id: previousSessionId,
          message: 'Task force released and now available for claiming.',
        });
      } catch (error) {
        return errorResponse(
          'release_failed',
          error instanceof Error ? error.message : 'Failed to force release task'
        );
      }
    }

    case 'complete_task': {
      const taskId = args.task_id as string;

      try {
        const task = await stateManager.getTask(taskId);
        if (!task) {
          return errorResponse('not_found', `Task ${taskId} not found`);
        }

        // Only allow completing if this session claimed it
        if (task.claimedBySessionId !== sessionId) {
          return errorResponse(
            'not_owner',
            'Cannot complete a task claimed by another session'
          );
        }

        const completed = await stateManager.completeTask(taskId);

        wsHandler.broadcast(sessionId, 'epic:task:completed', { taskId, epicId: task.epicId });

        return jsonResponse({
          success: true,
          task_id: completed.id,
          status: completed.status,
          completed_at: completed.completedAt,
          message: 'Task completed!',
        });
      } catch (error) {
        return errorResponse(
          'complete_failed',
          error instanceof Error ? error.message : 'Failed to complete task'
        );
      }
    }

    case 'delete_task': {
      const taskId = args.task_id as string;

      try {
        const task = await stateManager.getTask(taskId);
        if (!task) {
          return errorResponse('not_found', `Task ${taskId} not found`);
        }

        // Safety check: reject if task is actively claimed or in progress
        if (task.claimedBySessionId) {
          return errorResponse(
            'task_claimed',
            'Cannot delete a task that is actively claimed. Release the task first.'
          );
        }

        if (task.status === 'active' || task.status === 'in_progress') {
          return errorResponse(
            'task_in_progress',
            'Cannot delete a task that is in progress. Complete or release the task first.'
          );
        }

        // Delete task (cascades to features)
        await stateManager.deleteTask(taskId, userId);

        wsHandler.broadcast(sessionId, 'epic:task:deleted', { taskId, epicId: task.epicId });

        return jsonResponse({
          success: true,
          task_id: taskId,
          message: 'Task and all associated features deleted',
        });
      } catch (error) {
        return errorResponse(
          'delete_failed',
          error instanceof Error ? error.message : 'Failed to delete task'
        );
      }
    }

    case 'move_task': {
      const taskId = args.task_id as string;
      const targetEpicId = args.target_epic_id as string;

      try {
        const task = await stateManager.getTask(taskId);
        if (!task) {
          return errorResponse('not_found', `Task ${taskId} not found`);
        }

        // Safety check: reject if task is in progress
        if (task.status === 'active' || task.status === 'in_progress') {
          return errorResponse(
            'task_in_progress',
            'Cannot move a task that is in progress. Complete or release the task first.'
          );
        }

        // Verify target epic exists
        const targetEpic = await stateManager.getEpic(targetEpicId);
        if (!targetEpic) {
          return errorResponse('not_found', `Target epic ${targetEpicId} not found`);
        }

        // Check if task has dependencies that would break
        if (task.dependsOn && task.dependsOn.length > 0) {
          // Get all tasks in current epic to check dependency references
          const currentEpicTasks = await stateManager.listTasks(task.epicId);
          const targetEpicTasks = await stateManager.listTasks(targetEpicId);

          // Check if dependencies are within current epic (would break when moved)
          const crossEpicDeps = task.dependsOn.filter(depId => 
            !targetEpicTasks.find(t => t.id === depId)
          );

          if (crossEpicDeps.length > 0) {
            return errorResponse(
              'dependency_conflict',
              `Task has dependencies that don't exist in target epic: ${crossEpicDeps.join(', ')}. ` +
              `Remove dependencies before moving or ensure target epic contains the same tasks.`
            );
          }
        }

        // Move task and all features
        const movedTask = await stateManager.moveTask(taskId, targetEpicId);

        wsHandler.broadcast(sessionId, 'epic:task:moved', { 
          taskId, 
          fromEpicId: task.epicId, 
          toEpicId: targetEpicId 
        });

        return jsonResponse({
          success: true,
          task_id: movedTask.id,
          from_epic_id: task.epicId,
          to_epic_id: targetEpicId,
          message: `Task moved from ${task.epicId} to ${targetEpicId}`,
        });
      } catch (error) {
        return errorResponse(
          'move_failed',
          error instanceof Error ? error.message : 'Failed to move task'
        );
      }
    }

    default:
      return errorResponse('unknown_tool', `Unknown epic tool: ${name}`);
  }
}

