        },
      },
      required: [],
    },
  },
  {
    name: 'get_epic',
    description:
      'Get detailed information about an Epic including all its tasks.',
    inputSchema: {
      type: 'object' as const,
      properties: {
        epic_id: {
          type: 'string',
          description: 'Epic ID (e.g., "DATA-23")',
        },
      },
      required: ['epic_id'],
    },
  },
  {
    name: 'update_epic',
    description:
      'Update an Epic\'s metadata (title, description, status, priority).',
    inputSchema: {
      type: 'object' as const,
      properties: {
        epic_id: {
          type: 'string',
          description: 'Epic ID (e.g., "DATA-23")',
        },
