#!/usr/bin/env tsx
/**
 * Manual test script to verify delete_task and move_task MCP tools
 * 
 * This script demonstrates:
 * 1. Creating an epic with tasks and features
 * 2. Testing delete_task (should cascade to features)
 * 3. Testing move_task (should move task + update features epicId)
 */

import { FirestoreStateManager } from './server/state/firestore-manager.js';
import { Firestore } from '@google-cloud/firestore';

async function main() {
  console.log('='.repeat(80));
  console.log('Testing delete_task and move_task operations');
  console.log('='.repeat(80));

  // Initialize Firestore (uses emulator if FIRESTORE_EMULATOR_HOST is set)
  const db = new Firestore({
    projectId: 'aictrl-dev',
  });

  const stateManager = new FirestoreStateManager(db);

  try {
    // Test 1: Create test data
    console.log('\n📝 Test 1: Creating test epic with tasks...');

    const epic1 = await stateManager.createEpic('test-org-1', {
      title: 'Test Epic 1',
      shortKey: 'TEST1',
      description: 'First test epic',
    }, 'test-user');

    const epic2 = await stateManager.createEpic('test-org-1', {
