    const deletedFeatures = await stateManager.listFeatures(task1.id);

    console.log(`   Task exists after delete: ${deletedTask !== null}`);
    console.log(`   Task deletedAt set: ${deletedTask?.deletedAt !== undefined}`);
    console.log(`   Features after delete: ${deletedFeatures.length}`);
    console.log(`   Features soft-deleted: ${deletedFeatures.every(f => f.deletedAt !== undefined)}`);

    if (deletedTask && deletedTask.deletedAt && deletedFeatures.every(f => f.deletedAt)) {
      console.log('✅ delete_task works correctly (cascades to features)');
    } else {
      console.log('❌ delete_task failed');
    }

    // Test 3: Move task (should update task + features epicId)
    console.log('\n🚚 Test 3: Moving task2 to epic2...');

    console.log(`   Task2 current epicId: ${task2.epicId}`);
    console.log(`   Feature2 current epicId: ${feature2.epicId}`);

    const movedTask = await stateManager.moveTask(task2.id, epic2.id);

    console.log(`   Task2 new epicId: ${movedTask.epicId}`);

    // Verify features also updated
    const movedFeatures = await stateManager.listFeatures(task2.id);
    const movedFeature = movedFeatures.find(f => f.id === feature2.id);

    console.log(`   Feature2 new epicId: ${movedFeature?.epicId}`);

    if (movedTask.epicId === epic2.id && movedFeature?.epicId === epic2.id) {
      console.log('✅ move_task works correctly (updates task + features)');
    } else {
      console.log('❌ move_task failed');
    }

    // Test 4: Try to delete an active task (should fail)
    console.log('\n🛡️  Test 4: Safety check - trying to delete active task...');

    const activeTask = await stateManager.createTask({
      epicId: epic1.id,
      title: 'Active task',
      description: 'This should not be deletable',
    });

    // Mark as claimed (active)
    await stateManager.updateTask(activeTask.id, { status: 'active' });
    await stateManager.claimTask(activeTask.id, 'test-session');

    const claimedTask = await stateManager.getTask(activeTask.id);
    console.log(`   Task status: ${claimedTask?.status}`);
    console.log(`   Task claimed: ${claimedTask?.claimedBySessionId !== undefined}`);

    // Note: deleteTask doesn't have safety checks in StateManager - those are in MCP tool
    // So we just verify the state here
    if (claimedTask?.claimedBySessionId) {
      console.log('✅ Safety check: Task is claimed (would be rejected by MCP tool)');
    }

    console.log('\n' + '='.repeat(80));
    console.log('All tests completed successfully!');
    console.log('='.repeat(80));

  } catch (error) {
    console.error('\n❌ Test failed with error:', error);
    process.exit(1);
  }
}

